D,GACA,WAAA0T,GAAAjd,iBAAAuJ,GACA,WAAA0T,IAAA1T,EAAAlI,aAAAgR,aACA,SAAA4K,GAAArf,KAAAqC,UAAAuJ,OAAA,WAAAD,GA+BA,SAAA6d,EAAAC,GACA,IAAAvpB,OAAAwpB,OAAAC,YAAA,CAAA9b,KAAA,uBAAA+b,MAAAH,GAAA,KAAA,MAAAve,KA5BAke,EAAA9oB,EAAAG,MACA4oB,EAAA/oB,EAAAI,QACA4oB,EAAA,SAAAhpB,EAAAK,QACA2oB,EAAA,SAAAhpB,EAAAM,QACA0oB,EAAA,OAAAhpB,EAAAO,MAGAjB,GAAA,4BAAAyD,SAAA,SAAAkL,GACAA,EAAAtH,iBAAA,SAAA,WAAAmiB,EAAA7a,EAAAnH,QAAAmS,KAAAiQ,EAAA,CAAA/oB,KAAA8N,EAAAnH,QAAAmS,YAEA3Z,GAAA,iCAAAyD,SAAA,SAAAkL,GACAA,EAAAtH,iBAAA,SAAA,WAAAoiB,EAAA9a,EAAAnH,QAAAmS,KAAAiQ,EAAA,CAAA9oB,OAAA6N,EAAAnH,QAAAmS,YAEA,CAAA,SAAA,SAAA,QAAAlW,SAAA,SAAAgc,GACA,IAAAkK,EAAAhqB,EAAA,uBAAA8f,EAAA,MACAkK,GAAAA,EAAAtiB,iBAAA,SAAA,WACA,IAAA0E,GAAA4d,EAAAlnB,UAAA8L,SAAA,MACAmb,EAAAjK,EAAA1T,GACA6d,EAAA,CAAAK,CAAAxK,GAAA1T,UAIApM,EAAA,YAAA0H,iBAAA,SAAA,WACAkd,EAAA9hB,UAAAyF,OAAA,QACA,IAAA5H,OAAAwpB,OAAAC,YAAA,CAAA9b,KAAA,yBAAA,KAAA,MAAA3C,QAOAhL,OAAA+G,iBAAA,WAAA,SAAAiE,GACA,IAAAzC,EAAAyC,EAAA/F,MAAA,GACA,yBAAAsD,EAAAoF,KAAAsW,EAAA9hB,UAAAC,IAAA,QACA,2BAAAmG,EAAAoF,MAAAsW,EAAA9hB,UAAAyF,OAAA,WAGA,IAAA5H,OAAAwpB,OAAAC,YAAA,CAAA9b,KAAA,yBAAA,KAAA,MAAA3C","file":"bundle.js","sourcesContent":["/* ============================================================\r\n   CASA PESTALOZZI — Entry point JS\r\n   Gulp concatena src/js/**‌/*.js en orden alfabético de ruta:\r\n   1. app.js (este archivo) — define estado compartido + boot()\r\n   2. data/menu-data.js      — window.CP_MENU\r\n   3. modules/*.js            — funciones init*, split*, etc.\r\n   boot() se llama en DOMContentLoaded, cuando todo ya está definido.\r\n   ============================================================ */\r\n\r\n// ── Estado y utilidades compartidos ──────────────────────────\r\nvar $ = function(s, c) { return (c || document).querySelector(s); };\r\nvar $$ = function(s, c) { return Array.from((c || document).querySelectorAll(s)); };\r\nvar body = document.body;\r\nvar reduce = window.matchMedia(\"(prefers-reduced-motion: reduce)\").matches;\r\nvar isTouch = window.matchMedia(\"(pointer: coarse)\").matches;\r\nvar T = Object.assign({ hero: \"cinema\", accent: \"oro\", cursor: true, smooth: true, anim: true }, window.CP_TWEAKS || {});\r\nvar suppressClick = false;\r\n\r\n// Acento intercambiable\r\nvar ACCENTS = {\r\n  oro:       [\"#cca352\", \"#e0c184\"],\r\n  terracota: [\"#c06a36\", \"#dca072\"],\r\n  salvia:    [\"#88a37b\", \"#a9c19d\"]\r\n};\r\n\r\nfunction applyAccent(key) {\r\n  var a = ACCENTS[key] || ACCENTS.oro;\r\n  document.documentElement.style.setProperty(\"--accent\", a[0]);\r\n  document.documentElement.style.setProperty(\"--accent-soft\", a[1]);\r\n}\r\n\r\n// ── Boot ──────────────────────────────────────────────────────\r\nfunction boot() {\r\n  var yearEl = document.getElementById(\"year\");\r\n  if (yearEl) yearEl.textContent = new Date().getFullYear();\r\n  if (window.gsap && window.ScrollTrigger) gsap.registerPlugin(ScrollTrigger);\r\n\r\n  applyAccent(T.accent);\r\n  body.setAttribute(\"data-hero\", T.hero);\r\n  setCursorEnabled(T.cursor);\r\n  if (!T.anim) body.classList.add(\"no-anim\");\r\n\r\n  initCursor();\r\n  initMagnetic();\r\n  initNav();\r\n  initRail();\r\n  initFab();\r\n  initMenu();\r\n  initGallery();\r\n  initLightbox();\r\n  initHours();\r\n  initForm();\r\n  initTweaks();\r\n\r\n  if (window.gsap && window.ScrollTrigger) {\r\n    heroIntro();\r\n    initReveals();\r\n    initCounters();\r\n  } else {\r\n    $$(\"[data-reveal]\").forEach(function(el) { el.style.opacity = 1; el.style.transform = \"none\"; });\r\n  }\r\n\r\n  if (T.smooth) startLenis();\r\n  setTimeout(function() { if (window.ScrollTrigger) ScrollTrigger.refresh(); }, 600);\r\n}\r\n\r\nif (document.readyState === \"loading\") document.addEventListener(\"DOMContentLoaded\", boot);\r\nelse boot();\r\n","/* ── KDS — Área de Producción · Casa Pestalozzi ─────────────── */\n\nfunction initArea() {\n  if (!window.CP_AREA) return;\n  if (initArea._done) return;\n  initArea._done = true;\n\n  var AREA_ID     = window.CP_AREA.id;\n  var AREA_COLOR  = window.CP_AREA.color;\n  var pollTimer   = null;\n\n  var listEnv     = document.getElementById('list-enviados');\n  var listPrep    = document.getElementById('list-prep');\n  var listListo   = document.getElementById('list-listo');\n  var countEnv    = document.getElementById('count-enviados');\n  var countPrep   = document.getElementById('count-prep');\n  var countListo  = document.getElementById('count-listo');\n  var refreshInfo = document.getElementById('area-refresh-info');\n\n  // ── Helpers ────────────────────────────────────────────────\n  function escHtml(str) {\n    return String(str)\n      .replace(/&/g, '&amp;').replace(/</g, '&lt;')\n      .replace(/>/g, '&gt;').replace(/\"/g, '&quot;');\n  }\n\n  function minutosDesde(timestamp) {\n    var d = new Date(timestamp.replace(' ', 'T'));\n    var diff = Math.floor((Date.now() - d.getTime()) / 60000);\n    return diff < 0 ? 0 : diff;\n  }\n\n  // ── Carga y renderizado ────────────────────────────────────\n  function loadItems() {\n    fetch('/api/area-items?area_id=' + AREA_ID)\n      .then(function(r) { return r.json(); })\n      .then(function(data) {\n        if (!data.ok) return;\n        renderBoard(data.items);\n        var now = new Date();\n        if (refreshInfo) {\n          refreshInfo.textContent = 'Actualizado ' +\n            now.toLocaleTimeString('es-MX', { hour: '2-digit', minute: '2-digit' });\n        }\n      })\n      .catch(function() {\n        if (refreshInfo) refreshInfo.textContent = 'Error al cargar';\n      });\n  }\n\n  function renderBoard(items) {\n    // Agrupar por ticket_id\n    var byTicket = {};\n    var ticketOrder = [];\n    for (var i = 0; i < items.length; i++) {\n      var it = items[i];\n      if (!byTicket[it.ticket_id]) {\n        byTicket[it.ticket_id] = {\n          ticket_id:     it.ticket_id,\n          mesa_nombre:   it.mesa_nombre,\n          ticket_nombre: it.ticket_nombre,\n          enviados:      [],\n          prep:          [],\n          listos:        []\n        };\n        ticketOrder.push(it.ticket_id);\n      }\n      if (it.estado === 'enviado')          byTicket[it.ticket_id].enviados.push(it);\n      else if (it.estado === 'en_preparacion') byTicket[it.ticket_id].prep.push(it);\n      else if (it.estado === 'listo')       byTicket[it.ticket_id].listos.push(it);\n    }\n\n    var envCards   = [];\n    var prepCards  = [];\n    var listoCards = [];\n    var envCount = 0, prepCount = 0, listoCount = 0;\n\n    for (var ti = 0; ti < ticketOrder.length; ti++) {\n      var group = byTicket[ticketOrder[ti]];\n      if (group.enviados.length) {\n        envCards.push(buildCard(group, group.enviados, 'enviado'));\n        envCount += group.enviados.length;\n      }\n      if (group.prep.length) {\n        prepCards.push(buildCard(group, group.prep, 'prep'));\n        prepCount += group.prep.length;\n      }\n      if (group.listos.length) {\n        listoCards.push(buildCard(group, group.listos, 'listo'));\n        listoCount += group.listos.length;\n      }\n    }\n\n    var emptyEnv   = '<div class=\"area-empty\"><span class=\"area-empty__icon\">◌</span><span>Sin pedidos</span></div>';\n    var emptyOther = '<div class=\"area-empty\"><span class=\"area-empty__icon\">◌</span><span>—</span></div>';\n\n    listEnv.innerHTML   = envCards.length   ? envCards.join('')   : emptyEnv;\n    listPrep.innerHTML  = prepCards.length  ? prepCards.join('')  : emptyOther;\n    listListo.innerHTML = listoCards.length ? listoCards.join('') : emptyOther;\n\n    if (countEnv)   countEnv.textContent   = envCount;\n    if (countPrep)  countPrep.textContent  = prepCount;\n    if (countListo) countListo.textContent = listoCount;\n\n    bindAvanzar();\n  }\n\n  function buildCard(group, itemList, colType) {\n    var min     = minutosDesde(itemList[0].created_at);\n    var urgClass = min >= 10 ? ' area-card--urgente'\n                 : min >= 5  ? ' area-card--alerta' : '';\n\n    var mesaTxt = escHtml(group.mesa_nombre);\n    var clienteTxt = group.ticket_nombre\n      ? ' <span class=\"area-card__cliente\">— ' + escHtml(group.ticket_nombre) + '</span>'\n      : '';\n\n    var minTxt = min === 0 ? 'ahora' : 'hace ' + min + ' min';\n\n    var h = '<div class=\"area-card' + urgClass + '\">';\n    h += '<div class=\"area-card__head\">';\n    h += '<span class=\"area-card__mesa\">' + mesaTxt + clienteTxt + '</span>';\n    h += '<span class=\"area-card__time\">' + minTxt + '</span>';\n    h += '</div>';\n    h += '<div class=\"area-card__items\">';\n\n    for (var i = 0; i < itemList.length; i++) {\n      var it       = itemList[i];\n      var comLabel = it.comensal !== null ? 'C.' + it.comensal : 'GL';\n      var hasBack    = colType === 'prep' || colType === 'listo';\n      var hasForward = colType === 'enviado' || colType === 'prep';\n\n      h += '<div class=\"area-card__item\">';\n      var notaHtml = it.nota\n        ? '<span class=\"area-card__nota\">' + escHtml(it.nota) + '</span>'\n        : '';\n      h += '<div class=\"area-card__item-info\">';\n      h += '<span class=\"area-card__qty\">×' + it.cantidad + '</span>';\n      h += '<div class=\"area-card__name-wrap\">';\n      h += '<span class=\"area-card__name\">' + escHtml(it.nombre) + '</span>';\n      h += notaHtml;\n      h += '</div>';\n      h += '<span class=\"area-card__com\">' + comLabel + '</span>';\n      h += '</div>';\n\n      if (hasBack || hasForward) {\n        h += '<div class=\"area-card__item-btns\">';\n        if (hasBack) {\n          h += '<button class=\"area-card__btn area-card__btn--back\" data-id=\"' +\n               it.id + '\" data-dir=\"back\">← Devolver</button>';\n        }\n        if (colType === 'enviado') {\n          h += '<button class=\"area-card__btn area-card__btn--prep\" data-id=\"' +\n               it.id + '\" data-dir=\"fwd\">→ Prep</button>';\n        } else if (colType === 'prep') {\n          h += '<button class=\"area-card__btn area-card__btn--listo\" data-id=\"' +\n               it.id + '\" data-dir=\"fwd\">✓ Listo</button>';\n        }\n        h += '</div>';\n      }\n\n      h += '</div>';\n    }\n\n    h += '</div>';\n    h += '</div>';\n    return h;\n  }\n\n  // ── Avanzar estado ─────────────────────────────────────────\n  function bindAvanzar() {\n    var btns = document.querySelectorAll('.area-card__btn[data-id]');\n    for (var i = 0; i < btns.length; i++) {\n      (function(btn) {\n        btn.addEventListener('click', function() {\n          btn.disabled = true;\n          btn.classList.add('area-card__btn--loading');\n          var url = btn.dataset.dir === 'back'\n            ? '/api/retroceder-item'\n            : '/api/avanzar-item';\n          fetch(url, {\n            method:  'POST',\n            headers: { 'Content-Type': 'application/json' },\n            body:    JSON.stringify({ item_id: parseInt(btn.dataset.id, 10) })\n          })\n          .then(function(r) { return r.json(); })\n          .then(function(result) {\n            if (result.ok) {\n              loadItems();\n            } else {\n              btn.disabled = false;\n              btn.classList.remove('area-card__btn--loading');\n            }\n          })\n          .catch(function() {\n            btn.disabled = false;\n            btn.classList.remove('area-card__btn--loading');\n          });\n        });\n      })(btns[i]);\n    }\n  }\n\n  // ── Init + polling ─────────────────────────────────────────\n  loadItems();\n  pollTimer = setInterval(loadItems, 1000);\n}\n\n(function() {\n  function tryInitArea() {\n    if (document.body && document.body.dataset.page === 'area') initArea();\n  }\n  if (document.readyState === 'loading') {\n    document.addEventListener('DOMContentLoaded', tryInitArea);\n  } else {\n    tryInitArea();\n  }\n})();\n","/* Contadores animados */\r\nfunction initCounters() {\r\n  $$(\"[data-count]\").forEach(function(el) {\r\n    var target = parseFloat(el.getAttribute(\"data-count\"));\r\n    var suffix = el.getAttribute(\"data-suffix\") || \"\";\r\n    ScrollTrigger.create({\r\n      trigger: el, start: \"top 90%\", once: true,\r\n      onEnter: function() {\r\n        if (reduce) { el.textContent = target + suffix; return; }\r\n        var o = { v: 0 };\r\n        gsap.to(o, { v: target, duration: 1.6, ease: \"power2.out\", onUpdate: function() { el.textContent = Math.round(o.v) + suffix; } });\r\n      }\r\n    });\r\n  });\r\n}\r\n","/* Cursor personalizado */\r\nfunction initCursor() {\r\n  if (isTouch) return;\r\n  var dot = $(\".cursor-dot\"), ring = $(\".cursor-ring\"), label = $(\".clabel\");\r\n  var mx = innerWidth / 2, my = innerHeight / 2, rx = mx, ry = my;\r\n\r\n  window.addEventListener(\"mousemove\", function(e) {\r\n    mx = e.clientX; my = e.clientY;\r\n    dot.style.transform = \"translate(\" + mx + \"px,\" + my + \"px) translate(-50%,-50%)\";\r\n  });\r\n\r\n  function raf() {\r\n    rx += (mx - rx) * 0.18;\r\n    ry += (my - ry) * 0.18;\r\n    ring.style.transform = \"translate(\" + rx + \"px,\" + ry + \"px) translate(-50%,-50%)\";\r\n    requestAnimationFrame(raf);\r\n  }\r\n  raf();\r\n\r\n  var hoverSel = \"a, button, .dish, .gcard, [data-magnetic], [data-zoom], [data-cursor], input, select, textarea, .pill, .tw-opt, .tw-swatch, .tw-switch\";\r\n\r\n  document.addEventListener(\"mouseover\", function(e) {\r\n    var t = e.target.closest(hoverSel);\r\n    if (!t) return;\r\n    ring.classList.add(\"hover\");\r\n    var cl = t.getAttribute(\"data-cursor\");\r\n    if (cl) { ring.classList.add(\"labeled\"); label.textContent = cl; }\r\n  });\r\n\r\n  document.addEventListener(\"mouseout\", function(e) {\r\n    var t = e.target.closest(hoverSel);\r\n    if (!t) return;\r\n    ring.classList.remove(\"hover\", \"labeled\");\r\n    label.textContent = \"\";\r\n  });\r\n}\r\n\r\nfunction setCursorEnabled(on) {\r\n  body.classList.toggle(\"no-cursor\", !on);\r\n  var dot  = document.querySelector(\".cursor-dot\");\r\n  var ring = document.querySelector(\".cursor-ring\");\r\n  if (dot)  dot.style.display  = on && !isTouch ? \"\" : \"none\";\r\n  if (ring) ring.style.display = on && !isTouch ? \"\" : \"none\";\r\n  document.documentElement.style.setProperty(\"cursor\", on && !isTouch ? \"none\" : \"auto\");\r\n  body.style.cursor = on && !isTouch ? \"none\" : \"auto\";\r\n}\r\n","/* FAB flotante de reserva */\r\nfunction initFab() {\r\n  var fab = $(\"#reserveFab\");\r\n  var hero = $(\"#hero\");\r\n  var io = new IntersectionObserver(function(ent) {\r\n    ent.forEach(function(e) { fab.classList.toggle(\"show\", !e.isIntersecting); });\r\n  }, { threshold: 0.2 });\r\n  io.observe(hero);\r\n}\r\n","/* Formulario de reserva + calendario personalizado + hora picker */\r\n\r\n/* ---- Calendario ---- */\r\nfunction initCalendar() {\r\n  var wrap    = $(\"#datePicker\");\r\n  var display = $(\"#dateDisplay\");\r\n  var hidden  = $(\"#fechaHidden\");\r\n  var cal     = $(\"#cpCalendar\");\r\n  var label   = cal.querySelector(\".cpc-label\");\r\n  var grid    = cal.querySelector(\".cpc-grid\");\r\n  var prevBtn = cal.querySelector(\".cpc-prev\");\r\n  var nextBtn = cal.querySelector(\".cpc-next\");\r\n\r\n  var today    = new Date(); today.setHours(0,0,0,0);\r\n  var curYear  = today.getFullYear();\r\n  var curMonth = today.getMonth();\r\n  var selected = null;\r\n\r\n  var MONTHS = [\"Enero\",\"Febrero\",\"Marzo\",\"Abril\",\"Mayo\",\"Junio\",\"Julio\",\"Agosto\",\"Septiembre\",\"Octubre\",\"Noviembre\",\"Diciembre\"];\r\n\r\n  function pad(n) { return n < 10 ? \"0\" + n : \"\" + n; }\r\n\r\n  function render() {\r\n    label.textContent = MONTHS[curMonth] + \" \" + curYear;\r\n    grid.innerHTML = \"\";\r\n\r\n    var first = new Date(curYear, curMonth, 1).getDay();\r\n    var days  = new Date(curYear, curMonth + 1, 0).getDate();\r\n\r\n    for (var i = 0; i < first; i++) {\r\n      var empty = document.createElement(\"span\");\r\n      empty.className = \"cpc-day empty\";\r\n      grid.appendChild(empty);\r\n    }\r\n\r\n    for (var d = 1; d <= days; d++) {\r\n      var btn = document.createElement(\"button\");\r\n      btn.type = \"button\";\r\n      btn.className = \"cpc-day\";\r\n      btn.textContent = d;\r\n\r\n      var date = new Date(curYear, curMonth, d);\r\n      date.setHours(0,0,0,0);\r\n\r\n      if (date < today) {\r\n        btn.classList.add(\"disabled\");\r\n        btn.disabled = true;\r\n      }\r\n      if (date.getTime() === today.getTime()) btn.classList.add(\"today\");\r\n      if (selected && date.getTime() === selected.getTime()) btn.classList.add(\"selected\");\r\n\r\n      (function(dt) {\r\n        btn.addEventListener(\"click\", function() {\r\n          selected = dt;\r\n          hidden.value = dt.getFullYear() + \"-\" + pad(dt.getMonth() + 1) + \"-\" + pad(dt.getDate());\r\n          display.value = pad(dt.getDate()) + \" / \" + pad(dt.getMonth() + 1) + \" / \" + dt.getFullYear();\r\n          closeCalendar();\r\n        });\r\n      })(date);\r\n\r\n      grid.appendChild(btn);\r\n    }\r\n  }\r\n\r\n  function openCalendar() { cal.classList.add(\"open\"); cal.setAttribute(\"aria-hidden\",\"false\"); render(); }\r\n  function closeCalendar() { cal.classList.remove(\"open\"); cal.setAttribute(\"aria-hidden\",\"true\"); }\r\n\r\n  display.addEventListener(\"click\", function(e) { e.stopPropagation(); cal.classList.contains(\"open\") ? closeCalendar() : openCalendar(); });\r\n  prevBtn.addEventListener(\"click\", function(e) { e.stopPropagation(); curMonth--; if (curMonth < 0) { curMonth = 11; curYear--; } render(); });\r\n  nextBtn.addEventListener(\"click\", function(e) { e.stopPropagation(); curMonth++; if (curMonth > 11) { curMonth = 0; curYear++; } render(); });\r\n\r\n  document.addEventListener(\"click\", function(e) { if (!wrap.contains(e.target)) closeCalendar(); });\r\n}\r\n\r\n/* ---- Selector de hora ---- */\r\nfunction initHourPicker() {\r\n  var wrap     = $(\"#hourPicker\");\r\n  var display  = $(\"#hourDisplay\");\r\n  var hidden   = $(\"#horaHidden\");\r\n  var dropdown = $(\"#hourDropdown\");\r\n  var HOURS    = [\"09:00\",\"10:00\",\"11:00\",\"12:00\",\"13:00\",\"14:00\",\"15:00\",\"16:00\",\"17:00\",\"18:00\",\"19:00\",\"20:00\",\"21:00\"];\r\n\r\n  HOURS.forEach(function(h) {\r\n    var btn = document.createElement(\"button\");\r\n    btn.type = \"button\";\r\n    btn.className = \"hour-option\";\r\n    btn.textContent = h;\r\n    btn.addEventListener(\"click\", function(e) {\r\n      e.stopPropagation();\r\n      hidden.value = h;\r\n      display.value = h;\r\n      dropdown.querySelectorAll(\".hour-option\").forEach(function(b) { b.classList.remove(\"sel\"); });\r\n      btn.classList.add(\"sel\");\r\n      closeHourDropdown();\r\n    });\r\n    dropdown.appendChild(btn);\r\n  });\r\n\r\n  function closeHourDropdown() { dropdown.classList.remove(\"open\"); dropdown.setAttribute(\"aria-hidden\",\"true\"); }\r\n\r\n  display.addEventListener(\"click\", function(e) {\r\n    e.stopPropagation();\r\n    var isOpen = dropdown.classList.contains(\"open\");\r\n    // Close calendar if open\r\n    var cal = $(\"#cpCalendar\");\r\n    if (cal) { cal.classList.remove(\"open\"); cal.setAttribute(\"aria-hidden\",\"true\"); }\r\n    isOpen ? closeHourDropdown() : (dropdown.classList.add(\"open\"), dropdown.setAttribute(\"aria-hidden\",\"false\"));\r\n  });\r\n\r\n  document.addEventListener(\"click\", function(e) { if (!wrap.contains(e.target)) closeHourDropdown(); });\r\n}\r\n\r\n/* ---- Formulario ---- */\r\nfunction initForm() {\r\n  var form   = $(\"#reservaForm\");\r\n  var pills  = $$(\"#guestPills .pill\");\r\n  var extra  = $(\"#guestsExtra\");\r\n  var guests = 2;\r\n\r\n  pills.forEach(function(p) {\r\n    p.addEventListener(\"click\", function() {\r\n      pills.forEach(function(x) { x.classList.remove(\"sel\"); });\r\n      p.classList.add(\"sel\");\r\n      var g = p.getAttribute(\"data-g\");\r\n      if (g === \"6+\") {\r\n        extra.classList.add(\"show\");\r\n        guests = guestCount || 6;\r\n      } else {\r\n        extra.classList.remove(\"show\");\r\n        guests = g;\r\n      }\r\n    });\r\n  });\r\n\r\n  var stepVal   = $(\"#guestsVal\");\r\n  var stepHid   = $(\"#guestsNum\");\r\n  var stepMinus = $(\"#guestsMinus\");\r\n  var stepPlus  = $(\"#guestsPlus\");\r\n  var guestCount = 6;\r\n\r\n  function updateStepper() {\r\n    stepVal.textContent = guestCount;\r\n    stepHid.value = guestCount;\r\n    stepMinus.disabled = (guestCount <= 6);\r\n    guests = guestCount;\r\n  }\r\n\r\n  stepPlus.addEventListener(\"click\", function() { guestCount = Math.min(99, guestCount + 1); updateStepper(); });\r\n  stepMinus.addEventListener(\"click\", function() { guestCount = Math.max(6, guestCount - 1); updateStepper(); });\r\n\r\n  initCalendar();\r\n  initHourPicker();\r\n\r\n  var msg = $(\"#formMsg\");\r\n  form.addEventListener(\"submit\", function(e) {\r\n    e.preventDefault();\r\n    var nombre = form.nombre.value.trim();\r\n    var email  = form.email.value.trim();\r\n    var fecha  = $(\"#fechaHidden\").value;\r\n    var hora   = $(\"#horaHidden\").value;\r\n\r\n    if (!nombre || !email || !fecha || !hora) {\r\n      msg.textContent = \"Completa nombre, correo, fecha y hora.\";\r\n      msg.classList.add(\"show\");\r\n      if (!reduce) gsap.fromTo(form, { x: -6 }, { x: 0, duration: 0.4, ease: \"elastic.out(1,0.3)\" });\r\n      return;\r\n    }\r\n\r\n    msg.classList.remove(\"show\");\r\n\r\n    var data = new FormData();\r\n    data.append(\"nombre\", nombre);\r\n    data.append(\"email\", email);\r\n    data.append(\"fecha\", fecha);\r\n    data.append(\"hora\", hora);\r\n    data.append(\"comensales\", guests);\r\n    data.append(\"nota\", form.nota ? form.nota.value.trim() : \"\");\r\n\r\n    fetch(\"/reservar\", { method: \"POST\", body: data })\r\n      .then(function(r) { return r.json(); })\r\n      .then(function(res) {\r\n        if (res.ok) {\r\n          var fd  = new Date(fecha + \"T00:00:00\");\r\n          var fmt = fd.toLocaleDateString(\"es-MX\", { weekday: \"long\", day: \"numeric\", month: \"long\" });\r\n          $(\"#confirmText\").innerHTML = 'Gracias, <b style=\"color:var(--accent);font-weight:400\">' + nombre + '</b>. Mesa para <b style=\"color:var(--accent);font-weight:400\">' + guests + '</b> el <b style=\"color:var(--accent);font-weight:400\">' + fmt + '</b> a las <b style=\"color:var(--accent);font-weight:400\">' + hora + '</b>. Te esperamos.';\r\n          form.style.display = \"none\";\r\n          var confirm = $(\"#reservaConfirm\");\r\n          confirm.classList.add(\"show\");\r\n          if (window.ScrollTrigger) ScrollTrigger.refresh();\r\n        } else {\r\n          msg.textContent = res.msg || \"Error al guardar la reservación.\";\r\n          msg.classList.add(\"show\");\r\n          if (!reduce) gsap.fromTo(form, { x: -6 }, { x: 0, duration: 0.4, ease: \"elastic.out(1,0.3)\" });\r\n        }\r\n      })\r\n      .catch(function() {\r\n        msg.textContent = \"Error de conexión. Intenta de nuevo.\";\r\n        msg.classList.add(\"show\");\r\n      });\r\n  });\r\n}\r\n","/* Casa Pestalozzi — datos del menú según carta oficial */\nwindow.CP_MENU = [\n\n  /* ── DESAYUNOS ─────────────────────────────────────── */\n  {\n    id: \"desayunos\",\n    label: \"Desayunos\",\n    kicker: \"Hasta el mediodía\",\n    dishes: [\n      { n: \"Enmoladas\",              d: \"Rellenas de pollo (70 gr.) con láminas de plátano macho, crema, queso y aros de cebolla bañadas en mole negro de Oaxaca.\", p: 240, area: 'cocina', img: \"/build/images/comida-8.webp\",  tags: [\"Especialidad C.P.\"] },\n      { n: \"Enchiladas Suizas\",      d: \"Enchiladas verdes rellenas de pollo (70 gr.), gratinadas con queso gouda, crema y aros de cebolla.\", p: 220, area: 'cocina', img: \"/build/images/comida-8.webp\" },\n      { n: \"Cecina y Huevo con Chorizo\", d: \"Cecina (130 gr.), huevos revueltos (2 pzas) con chorizo, acompañados de frijoles refritos con queso.\", p: 220, area: 'cocina', img: \"/build/images/comida-5.webp\" },\n      { n: \"Cazuela Cascabel\",       d: \"3 huevos estrellados o revueltos en salsa de chile cascabel, queso oaxaca gratinado, aguacate y una rebanada de pan hogaza.\", p: 220, area: 'cocina', img: \"/build/images/comida-5.webp\" },\n      { n: \"Sopes con Cecina o Arrachera\", d: \"3 sopes hechos a mano con frijoles, lechuga, crema, queso y cecina (130 gr.). Cambio de proteína con arrachera (150 gr.) +$40.\", p: 220, area: 'cocina', img: \"/build/images/comida-5.webp\" },\n      { n: \"Enfrijoladas\",           d: \"Rellenas de huevo revuelto, bañadas con salsa de frijol, chorizo, crema y queso.\", p: 220, area: 'cocina', img: \"/build/images/comida-5.webp\" },\n      { n: \"Huevos al Parmesano\",    d: \"2 huevos estrellados acompañados con espárragos blanqueados, arúgula, tocino y parmesano rallado.\", p: 210, area: 'cocina', img: \"/build/images/comida-4.webp\",  tags: [\"Brunch\"] },\n      { n: \"Omelette Fitness\",       d: \"Claras de huevo (2 pzas), espinaca, queso de cabra y láminas de aguacate.\", p: 190, area: 'cocina', img: \"/build/images/comida-4.webp\" },\n      { n: \"Toast de Salmón Ahumado\", d: \"Pan brioche, crema ácida, salmón ahumado (70 gr.), ajonjolí, 1 huevo estrellado, espárragos y aguacate.\", p: 230, area: 'cocina', img: \"/build/images/comida-9.webp\", tags: [\"Estrella\"] },\n      { n: \"Pan Francés Estilo C.P.\", d: \"Base de pan brioche con crema dulce, frutos rojos y miel de maple.\", p: 210, area: 'cocina', img: \"/build/images/comida-4.webp\", tags: [\"Dulce\"] },\n      { n: \"Huevos Módena\",          d: \"2 huevos revueltos o estrellados con tocino, queso parmesano y arúgula.\", p: 190, area: 'cocina', img: \"/build/images/comida-4.webp\" },\n      { n: \"Huevos Italianos\",       d: \"2 huevos en omelette, jamón serrano, láminas de queso parmesano y arúgula.\", p: 190, area: 'cocina', img: \"/build/images/comida-4.webp\" },\n      { n: \"Huevos Pamplona\",        d: \"2 huevos en omelette con chorizo español de pamplona, arúgula y queso mozarella fresco.\", p: 190, area: 'cocina', img: \"/build/images/comida-4.webp\" },\n      { n: \"Huevos al Sano\",         d: \"2 huevos en omelette con jamón de pavo, arúgula, queso mozarella fresco y jitomate cherry.\", p: 190, area: 'cocina', img: \"/build/images/comida-4.webp\" },\n      { n: \"Huevos al Gusto\",        d: \"Rancheros, a la mexicana, divorciados, al albañil, con tocino, con chorizo o con jamón.\", p: 180, area: 'cocina', img: \"/build/images/comida-5.webp\" },\n      { n: \"Molletes\",               d: \"4 piezas de pan baguette con frijoles y queso manchego, acompañado de pico de gallo.\", p: 100, area: 'cocina', img: \"/build/images/comida-1.webp\" },\n      { n: \"Casa Pestalozzi\",        d: \"½ orden de chilaquiles (40 gr.) con salsa al gusto, crema, queso y 2 huevos revueltos.\", p: 180, area: 'cocina', img: \"/build/images/comida-5.webp\" },\n      { n: \"Chilaquiles\",            d: \"Verdes, rojos o salsa de la casa, con pollo (30 gr.) o huevo (1 pza), queso, crema y cebolla morada. Con arrachera +$90 · con cecina +$65.\", p: 180, area: 'cocina', img: \"/build/images/comida-5.webp\" },\n      { n: \"Baguette de Jamón Serrano\", d: \"Jamón serrano, láminas de parmesano, casse de jitomate y arúgula.\", p: 220, area: 'cocina', img: \"/build/images/comida-8.webp\" },\n      { n: \"Baguette de Magret de Pollo\", d: \"Pollo a la plancha con queso gouda, rodajas de jitomate, mix de lechuga y aderezo cipriani.\", p: 220, area: 'cocina', img: \"/build/images/comida-8.webp\" },\n      { n: \"Baguette con Arrachera\", d: \"Arrachera (150 gr.), cremoso de aguacate con un toque de chipotle y mix de lechugas.\", p: 230, area: 'cocina', img: \"/build/images/comida-10.webp\" },\n      { n: \"Croissant con Jamón de Pavo\", d: \"Pechuga de pavo (120 gr.), queso gouda, aderezo cipriani, jitomate y mix de lechugas.\", p: 165, area: 'cocina', img: \"/build/images/comida-8.webp\" },\n      { n: \"Croissant con Huevo y Estragón\", d: \"2 pzas de huevo revuelto con estragón y mix de lechugas.\", p: 140, area: 'cocina', img: \"/build/images/comida-4.webp\" },\n      { n: \"Baguette de Cochinita\",  d: \"Cochinita (150 gr.), cebolla encurtida y habanero.\", p: 210, area: 'cocina', img: \"/build/images/comida-8.webp\" },\n      { n: \"Plato de Fruta Mixta\",   d: \"Fruta de temporada.\", p: 110, area: 'jugos', img: \"/build/images/comida-2.webp\" },\n      { n: \"Copa Antioxidante\",      d: \"Fresa, frambuesa, mora y zarzamora con yogurt y granola hecha en casa.\", p: 130, area: 'jugos', img: \"/build/images/comida-2.webp\" }\n    ]\n  },\n\n  /* ── ENTRADAS ──────────────────────────────────────── */\n  {\n    id: \"entradas\",\n    label: \"Entradas\",\n    kicker: \"Para comenzar\",\n    dishes: [\n      { n: \"Aros de Calamar\",        d: \"Empanizados, aderezo cipriani, chiles cuaresmeños y limón eureka.\", p: 210, area: 'cocina', img: \"/build/images/comida-1.webp\", tags: [\"Especialidad C.P.\"] },\n      { n: \"Tostadas de Atún\",       d: \"3 tostaditas con cubos de atún marinado en salsa oriental, cremoso de aguacate y poro.\", p: 195, area: 'cocina', img: \"/build/images/comida-9.webp\", tags: [\"Especialidad C.P.\"] },\n      { n: \"Torreta de Salmón\",      d: \"Salmón ahumado, queso cabra, aguacate, jitomate con aderezo de pesto de albahaca.\", p: 220, area: 'cocina', img: \"/build/images/comida-9.webp\", tags: [\"Especialidad C.P.\"] },\n      { n: \"Tiradito de Atún\",       d: \"Láminas de atún, aceite de chile, mayonesa spicy, toronja y eneldo.\", p: 210, area: 'cocina', img: \"/build/images/comida-9.webp\" },\n      { n: \"Carpaccio de Salmón\",    d: \"Finas láminas de salmón ahumado, arúgula, queso parmesano, alcaparras, limón eureka y jitomate cherry.\", p: 180, area: 'cocina', img: \"/build/images/comida-9.webp\" },\n      { n: \"Camarones al Ajillo\",    d: \"Salteados al olivo, ajo, peperoncino con pan de baguette.\", p: 210, area: 'cocina', img: \"/build/images/comida-1.webp\" },\n      { n: \"Espárragos al Horno\",    d: \"Queso gouda, tocino con reducción de balsámico.\", p: 180, area: 'horno', img: \"/build/images/comida-1.webp\" },\n      { n: \"Queso Burrata con Jitomates Cherrys\", d: \"Queso burrata con jitomates cherrys al horno, aceite de oliva, poro y hojas de albahaca.\", p: 210, area: 'horno', img: \"/build/images/comida-6.webp\" }\n    ]\n  },\n\n  /* ── SOPAS & CREMAS ────────────────────────────────── */\n  {\n    id: \"sopas\",\n    label: \"Sopas & Cremas\",\n    kicker: \"De temporada\",\n    dishes: [\n      { n: \"Crema del Día\",          d: \"Nuestras cremas y sopas son elaboradas por temporada y en nuestros especiales de fin de semana. Pregunta al mesero por la opción del día.\", p: 180, area: 'cocina', img: \"/build/images/comida-2.webp\", tags: [\"Temporada\"] },\n      { n: \"Sopa Especial de Fin de Semana\", d: \"Receta de la casa, elaborada con ingredientes frescos de temporada. Disponible sábados y domingos.\", p: 180, area: 'cocina', img: \"/build/images/comida-2.webp\", tags: [\"Fin de semana\"] }\n    ]\n  },\n\n  /* ── PASTAS ────────────────────────────────────────── */\n  {\n    id: \"pastas\",\n    label: \"Pastas\",\n    kicker: \"Ingredientes 100% italianos\",\n    dishes: [\n      { n: \"Fetuccini a los Cuatro Quesos y Camarones\", d: \"Queso brie, parmesano, queso crema y queso gouda.\", p: 280, area: 'cocina', img: \"/build/images/comida-7.webp\", tags: [\"Especialidad C.P.\"] },\n      { n: \"Lasagna de Filete de Res\", d: \"Cocción a baja temperatura por 3 horas con ingredientes 100% italianos.\", p: 280, area: 'cocina', img: \"/build/images/comida-7.webp\", tags: [\"Especialidad C.P.\"] },\n      { n: \"Rigatoni al Limón con Camarones y Parmesano\", d: \"Camarones salteados con vino blanco, mantequilla, ralladura de limón eureka y toque de albahaca.\", p: 280, area: 'cocina', img: \"/build/images/mejor-2.webp\", tags: [\"Estrella\"] },\n      { n: \"Spaguetti a l'Arrabbiata con Camarones y Parmesano\", d: \"Salsa de pomodoro con peperoncino.\", p: 280, area: 'cocina', img: \"/build/images/comida-7.webp\" },\n      { n: \"Spaguetti a la Boloñesa\", d: \"Cocción a baja temperatura por 3 horas con ingredientes 100% italianos.\", p: 280, area: 'cocina', img: \"/build/images/comida-7.webp\" },\n      { n: \"Spaguetti al Pomodoro y Parmesano\", d: \"Pasta, salsa de jitomate y parmesano.\", p: 190, area: 'cocina', img: \"/build/images/comida-7.webp\" }\n    ]\n  },\n\n  /* ── PLATOS FUERTES ────────────────────────────────── */\n  {\n    id: \"fuertes\",\n    label: \"Platos Fuertes\",\n    kicker: \"Cocina de autor\",\n    dishes: [\n      { n: \"Filete de Res en su Jugo\", d: \"Filete de res importado en su jugo con puré de papa rústico y espárragos al horno.\", p: 320, area: 'cocina', img: \"/build/images/mejor-6.webp\", tags: [\"Especialidad C.P.\"] },\n      { n: \"Salmón al Horno\",         d: \"Salmón noruego sazonado con ajo y aceite de oliva. Acompaña con media orden de pasta o ensalada.\", p: 295, area: 'cocina', img: \"/build/images/comida-9.webp\" },\n      { n: \"Hamburguesa de la Casa\",  d: \"Carne wagyu, pan brioche hecho en C.P., cebolla caramelizada, queso cheddar, mayonesa ahumada, pepinillo encurtido. Acompaña con papas gajo.\", p: 260, area: 'cocina', img: \"/build/images/comida-5.webp\", tags: [\"Especialidad C.P.\"] },\n      { n: \"Atún Sellado\",            d: \"Atún importado, sellado en costra de pistache, aderezo cipriani. Acompaña con mix de lechugas.\", p: 285, area: 'cocina', img: \"/build/images/comida-9.webp\" },\n      { n: \"Tacos de Cochinita\",      d: \"Tres tacos de tortilla de maíz hechas a mano, frijol, cebolla y habanero encurtido.\", p: 210, area: 'cocina', img: \"/build/images/comida-5.webp\", tags: [\"Especialidad C.P.\"] },\n      { n: \"Tacos de Vacío\",          d: \"Vacío importado, tortillas hechas a mano, salsa de piña con habanero y aguacate.\", p: 210, area: 'cocina', img: \"/build/images/comida-5.webp\" },\n      { n: \"Tacos de Camarón Rebozados\", d: \"Tres tortillas de harina, camarones rebozados, col morada y aderezo de chipotle.\", p: 240, area: 'cocina', img: \"/build/images/comida-1.webp\" },\n      { n: \"Vacío en Escalopas\",      d: \"Vacío importado en escalopas, arúgula, láminas de parmesano y reducción de bálsamico.\", p: 280, area: 'cocina', img: \"/build/images/mejor-6.webp\", tags: [\"Especialidad C.P.\"] },\n      { n: \"New York (450 grs.)\",     d: \"Carne calidad choice angus, cebollitas asadas, chiles toreados y papas a la francesa.\", p: 785, area: 'cocina', img: \"/build/images/mejor-6.webp\", tags: [\"Premium\"] },\n      { n: \"Rib Eye (450 grs.)\",      d: \"Carne calidad choice angus, cebollitas asadas, chiles toreados y papas a la francesa.\", p: 785, area: 'cocina', img: \"/build/images/mejor-6.webp\", tags: [\"Premium\"] }\n    ]\n  },\n\n  /* ── ENSALADAS ─────────────────────────────────────── */\n  {\n    id: \"ensaladas\",\n    label: \"Ensaladas\",\n    kicker: \"Frescas y de temporada\",\n    dishes: [\n      { n: \"Frutos Rojos\",            d: \"Mix de lechugas, frambuesas, zarzamoras, fresas, queso cabra, nuez y reducción de balsámico.\", p: 210, area: 'cocina', img: \"/build/images/comida-2.webp\" },\n      { n: \"Ciruela Betabel\",         d: \"Mix de lechugas, ciruela y betabel sazonado con estragón, queso burrata y almendras horneadas.\", p: 210, area: 'cocina', img: \"/build/images/comida-2.webp\", tags: [\"Especialidad C.P.\"] },\n      { n: \"Magret de Pollo\",         d: \"Pechuga de pollo prensada, lechuga baby asada, almendras horneadas con aderezo de queso.\", p: 210, area: 'cocina', img: \"/build/images/comida-2.webp\", tags: [\"Especialidad C.P.\"] },\n      { n: \"Jamón Serrano con Perlas de Melón\", d: \"Mix de lechugas, perlas de melón, jamón serrano, nuez y reducción de balsámico.\", p: 210, area: 'cocina', img: \"/build/images/comida-2.webp\" },\n      { n: \"Pasta Corta con Pollo\",   d: \"Mix de lechuga con cremoso de aguacate y almendras horneadas.\", p: 210, area: 'cocina', img: \"/build/images/comida-7.webp\" }\n    ]\n  },\n\n  /* ── PIZZAS ────────────────────────────────────────── */\n  {\n    id: \"pizzas\",\n    label: \"Pizzas\",\n    kicker: \"Horno de piedra\",\n    dishes: [\n      { n: \"Margarita\",               d: \"Pomodoro, mozzarella y albahaca.\", p: 190, area: 'horno', img: \"/build/images/comida-3.webp\" },\n      { n: \"Burrata\",                 d: \"Pomodoro, burrata, prosciutto y arúgula.\", p: 260, area: 'horno', img: \"/build/images/pizza-3.webp\", tags: [\"Favorita\"] },\n      { n: \"Milano\",                  d: \"Pomodoro, mozzarella, jitomates cherrys, salami y láminas de parmesano.\", p: 260, area: 'horno', img: \"/build/images/pizza-1.webp\" },\n      { n: \"Camarones a los 4 Quesos\", d: \"Salsa de 4 quesos, queso mozzarella y camarones.\", p: 260, area: 'horno', img: \"/build/images/pizza-2.webp\" }\n    ]\n  },\n\n  /* ── PARA PICAR ────────────────────────────────────── */\n  {\n    id: \"picar\",\n    label: \"Para Picar\",\n    kicker: \"Para compartir\",\n    dishes: [\n      { n: \"Mix de 3 Brusquetas\",    d: \"Jamón serrano, queso brie, anchoas.\", p: 160, area: 'cocina', img: \"/build/images/comida-1.webp\", tags: [\"3 piezas\"] },\n      { n: \"Aceitunas Temperadas con Aceite de Chile\", d: \"Aceitunas verdes en aceite de chiles.\", p: 160, area: 'cocina', img: \"/build/images/mejor-1.webp\" },\n      { n: \"Tabla Mixta\",            d: \"Queso parmesano, brie, manchego, chorizo salamanca, semillas, frutos rojos.\", p: 320, area: 'cocina', img: \"/build/images/comida-6.webp\" },\n      { n: \"Papas a la Francesa con Parmesano\", d: \"Papas a la francesa con queso parmesano rallado.\", p: 160, area: 'cocina', img: \"/build/images/comida-10.webp\" }\n    ]\n  },\n\n  /* ── CAFÉ & BEBIDAS ─────────────────────────────────── */\n  {\n    id: \"cafe\",\n    label: \"Café & Bebidas\",\n    kicker: \"Barra de Café\",\n    dishes: [\n      { n: \"Café Americano\",     d: \"Café de filtro, largo o corto al gusto.\", p: 65,  area: 'cafe', img: \"/build/images/comida-1.webp\" },\n      { n: \"Cappuccino\",         d: \"Espresso doble con espuma de leche vaporizada.\", p: 75, area: 'cafe', img: \"/build/images/comida-1.webp\" },\n      { n: \"Latte\",              d: \"Espresso con leche vaporizada y una fina capa de espuma.\", p: 80, area: 'cafe', img: \"/build/images/comida-1.webp\" },\n      { n: \"Café de Olla\",       d: \"Preparado con canela y piloncillo.\", p: 65, area: 'cafe', img: \"/build/images/comida-1.webp\" },\n      { n: \"Té / Infusión\",      d: \"Selección de tés y hierbas de temporada.\", p: 65, area: 'cafe', img: \"/build/images/comida-1.webp\" },\n      { n: \"Chocolate Caliente\", d: \"Chocolate artesanal con leche vaporizada.\", p: 80, area: 'cafe', img: \"/build/images/comida-1.webp\" },\n      { n: \"Agua Fresca\",        d: \"Agua de temporada del día.\", p: 60, area: 'cafe', img: \"/build/images/comida-2.webp\" },\n      { n: \"Refresco\",           d: \"Lata de refresco.\", p: 55, area: 'cafe', img: \"/build/images/comida-1.webp\" }\n    ]\n  },\n\n  /* ── JUGOS & SMOOTHIES ──────────────────────────────── */\n  {\n    id: \"jugos\",\n    label: \"Jugos & Smoothies\",\n    kicker: \"Barra de Jugos\",\n    dishes: [\n      { n: \"Jugo de Naranja\",    d: \"Naranja fresca exprimida al momento.\", p: 85,  area: 'jugos', img: \"/build/images/comida-2.webp\" },\n      { n: \"Jugo Verde\",         d: \"Pepino, apio, espinaca, limón y jengibre.\", p: 95, area: 'jugos', img: \"/build/images/comida-2.webp\" },\n      { n: \"Limonada Natural\",   d: \"Limón fresco con agua mineral y hierbabuena.\", p: 75, area: 'jugos', img: \"/build/images/comida-2.webp\" },\n      { n: \"Smoothie de Fresa\",  d: \"Fresa, yogurt griego, miel y granola.\", p: 100, area: 'jugos', img: \"/build/images/comida-2.webp\" },\n      { n: \"Agua de Coco\",       d: \"Agua de coco natural.\", p: 90,  area: 'jugos', img: \"/build/images/comida-2.webp\" }\n    ]\n  }\n\n];\n\n/* Mapeo de áreas de producción (slug → info) */\nwindow.CP_AREAS = {\n  cafe:   { id: 1, label: 'Barra de Café',   color: '#7b5e3a' },\n  jugos:  { id: 2, label: 'Barra de Jugos',  color: '#e8a920' },\n  cocina: { id: 3, label: 'Cocina',           color: '#b03a2e' },\n  horno:  { id: 4, label: 'Horno Napolitano', color: '#1a5276' },\n};\n","/* Galería \"Lo mejor de la casa\" — drag to scroll */\r\nvar GALLERY = [\r\n  { img: \"/build/images/mejor-2.webp\", n: \"Tagliatelle al Limón\", t: \"Pasta\" },\r\n  { img: \"/build/images/mejor-5.webp\", n: \"Camarones a la Brasa\", t: \"Mariscos\" },\r\n  { img: \"/build/images/pizza-3.webp\", n: \"Pizza al Horno de Piedra\", t: \"Pizzas\" },\r\n  { img: \"/build/images/mejor-3.webp\", n: \"Tostas de la Casa\", t: \"Para Picar\" },\r\n  { img: \"/build/images/mejor-4.webp\", n: \"Espresso Martini\", t: \"Coctelería\" },\r\n  { img: \"/build/images/mejor-6.webp\", n: \"Rib Eye 400 gr\", t: \"Cortes\" },\r\n  { img: \"/build/images/mejor-1.webp\", n: \"Aceitunas Temperadas\", t: \"Aperitivo\" }\r\n];\r\n\r\nfunction initGallery() {\r\n  var track = $(\"#galleryTrack\");\r\n  GALLERY.forEach(function(g) {\r\n    var c = document.createElement(\"div\");\r\n    c.className = \"gcard\";\r\n    c.setAttribute(\"data-cursor\", \"Arrastrar\");\r\n    c.setAttribute(\"data-zoom\", \"\");\r\n    c.setAttribute(\"data-zoom-name\", g.n);\r\n    c.setAttribute(\"data-zoom-cat\", g.t);\r\n    c.innerHTML = '<img src=\"' + g.img + '\" alt=\"' + g.n + '\" loading=\"lazy\" draggable=\"false\" /><div class=\"gcard__cap\"><div class=\"t\">' + g.t + '</div><div class=\"n\">' + g.n + '</div></div>';\r\n\r\n    // Direct click handler — bypasses event delegation issues with pointer capture\r\n    (function(card) {\r\n      card.addEventListener(\"click\", function(e) {\r\n        e.stopPropagation();\r\n        if (!suppressClick && window.__openZoom) window.__openZoom(card);\r\n      });\r\n    })(c);\r\n\r\n    track.appendChild(c);\r\n  });\r\n\r\n  var isDown = false, startX = 0, scrollStart = 0, moved = 0, pos = 0;\r\n  var max = function() { return Math.max(0, track.scrollWidth - track.clientWidth + 8); };\r\n  function setPos(p) { pos = Math.max(-max(), Math.min(0, p)); track.style.transform = \"translateX(\" + pos + \"px)\"; }\r\n\r\n  track.addEventListener(\"pointerdown\", function(e) { isDown = true; moved = 0; startX = e.clientX; scrollStart = pos; track.setPointerCapture(e.pointerId); });\r\n  track.addEventListener(\"pointermove\", function(e) {\r\n    if (!isDown) return;\r\n    var dx = e.clientX - startX;\r\n    moved += Math.abs(e.movementX || 0);\r\n    if (moved > 15) suppressClick = true;\r\n    setPos(scrollStart + dx);\r\n  });\r\n  var up = function() { isDown = false; setTimeout(function() { suppressClick = false; }, 60); };\r\n  track.addEventListener(\"pointerup\", up);\r\n  track.addEventListener(\"pointercancel\", up);\r\n  track.addEventListener(\"pointerleave\", up);\r\n  track.addEventListener(\"wheel\", function(e) {\r\n    if (Math.abs(e.deltaX) > Math.abs(e.deltaY)) { e.preventDefault(); setPos(pos - e.deltaX); }\r\n  }, { passive: false });\r\n}\r\n","/* Hero — split-text + intro + parallax */\r\nfunction splitTitle() {\r\n  var el = $(\"[data-split]\");\r\n  if (!el) return [];\r\n  var lines = [[]];\r\n  el.childNodes.forEach(function(node) {\r\n    if (node.nodeName === \"BR\") lines.push([]);\r\n    else (node.textContent || \"\").split(\"\").forEach(function(ch) { lines[lines.length - 1].push(ch); });\r\n  });\r\n  el.innerHTML = \"\";\r\n  var chars = [];\r\n  lines.forEach(function(ln) {\r\n    if (!ln.length) return;\r\n    var word = document.createElement(\"span\");\r\n    word.className = \"word\";\r\n    ln.forEach(function(ch) {\r\n      var s = document.createElement(\"span\");\r\n      s.className = \"char\";\r\n      s.textContent = ch;\r\n      word.appendChild(s);\r\n      chars.push(s);\r\n    });\r\n    el.appendChild(word);\r\n  });\r\n  return chars;\r\n}\r\n\r\nfunction heroIntro() {\r\n  var chars = splitTitle();\r\n  if (reduce || !window.gsap) { gsap.set(\"[data-split] .char\", { y: 0, opacity: 1 }); return; }\r\n\r\n  var tl = gsap.timeline({ delay: 0.25 });\r\n  gsap.set(chars, { yPercent: 115, opacity: 0 });\r\n  tl.to(chars, { yPercent: 0, opacity: 1, duration: 1.1, stagger: 0.045, ease: \"power4.out\" });\r\n  tl.from(\".hero__eyebrow\", { opacity: 0, y: 20, duration: 0.8 }, 0.2);\r\n  tl.to($$(\".hero__inner [data-reveal]\"), { opacity: 1, y: 0, duration: 0.9, stagger: 0.12, ease: \"power3.out\" }, \"-=0.7\");\r\n\r\n  var bg = $(\"[data-parallax-bg] img\");\r\n  if (bg) gsap.to(bg, { yPercent: -10, ease: \"none\", scrollTrigger: { trigger: \"#hero\", start: \"top top\", end: \"bottom top\", scrub: true } });\r\n}\r\n","/* Horario — resalta el día actual */\r\nfunction initHours() {\r\n  var today = new Date().getDay();\r\n  var row = $(\".reserva__hours .row[data-day=\\\"\" + today + \"\\\"]\");\r\n  if (row) {\r\n    row.classList.add(\"today\");\r\n    var v = row.querySelector(\"span:last-child\");\r\n    if (v) v.innerHTML = \"<b>\" + v.textContent + \"</b> · Hoy\";\r\n  }\r\n}\r\n","/* Smooth scroll — Lenis */\r\nvar lenis = null;\r\n\r\nfunction startLenis() {\r\n  if (lenis || isTouch || reduce || !window.Lenis) return;\r\n  lenis = new Lenis({ duration: 1.15, easing: function(t) { return Math.min(1, 1.001 - Math.pow(2, -10 * t)); }, smoothWheel: true });\r\n  lenis.on(\"scroll\", function() { if (window.ScrollTrigger) ScrollTrigger.update(); });\r\n  gsap.ticker.add(lenisRaf);\r\n  gsap.ticker.lagSmoothing(0);\r\n}\r\n\r\nfunction lenisRaf(time) { if (lenis) lenis.raf(time * 1000); }\r\n\r\nfunction stopLenis() {\r\n  if (!lenis) return;\r\n  gsap.ticker.remove(lenisRaf);\r\n  lenis.destroy();\r\n  lenis = null;\r\n}\r\n\r\nfunction scrollTo(target) {\r\n  var el = typeof target === \"string\" ? $(target) : target;\r\n  if (!el) return;\r\n  if (lenis) lenis.scrollTo(el, { offset: 0, duration: 1.3 });\r\n  else el.scrollIntoView({ behavior: reduce ? \"auto\" : \"smooth\" });\r\n}\r\n","/* Lightbox universal — cualquier [data-zoom] */\r\nfunction injectBadges() {\r\n  $$(\"[data-zoom]\").forEach(function(el) {\r\n    if (el.classList.contains(\"dish__thumb\")) return;\r\n    if (el.classList.contains(\"gcard\")) return;\r\n    if (el.querySelector(\":scope > .zoom-badge\")) return;\r\n    var b = document.createElement(\"span\");\r\n    b.className = \"zoom-badge\";\r\n    b.textContent = \"⤢ Ampliar\";\r\n    el.appendChild(b);\r\n    if (!el.hasAttribute(\"data-cursor\")) el.setAttribute(\"data-cursor\", \"Ampliar\");\r\n  });\r\n}\r\n\r\nfunction getZoomList() {\r\n  var list = [];\r\n  $$(\"[data-zoom]\").forEach(function(el) {\r\n    var img = el.tagName === \"IMG\" ? el : el.querySelector(\"img\");\r\n    var src = el.getAttribute(\"data-zoom-src\") || (img && (img.currentSrc || img.getAttribute(\"src\")));\r\n    if (!src) return;\r\n    list.push({ src: src, n: el.getAttribute(\"data-zoom-name\") || (img && img.alt) || \"\", t: el.getAttribute(\"data-zoom-cat\") || \"\", el: el });\r\n  });\r\n  return list;\r\n}\r\n\r\nfunction initLightbox() {\r\n  injectBadges();\r\n  var lb = $(\"#lightbox\"), lbImg = $(\"#lbImg\"), lbN = $(\"#lbN\"), lbT = $(\"#lbT\"), lbCur = $(\"#lbCur\"), lbTotal = $(\"#lbTotal\");\r\n  var list = [], idx = 0;\r\n\r\n  function render() {\r\n    var g = list[idx]; if (!g) return;\r\n    lbImg.src = g.src; lbImg.alt = g.n; lbN.textContent = g.n; lbT.textContent = g.t;\r\n    lbCur.textContent = idx + 1; lbTotal.textContent = list.length;\r\n    if (!reduce && window.gsap) gsap.fromTo(lbImg, { opacity: 0, scale: 0.97 }, { opacity: 1, scale: 1, duration: 0.45, ease: \"power2.out\" });\r\n  }\r\n\r\n  function groupId(el) { var s = el.closest(\"section, header\"); return s ? s.id : \"\"; }\r\n\r\n  function open(el) {\r\n    var g = groupId(el);\r\n    list = getZoomList().filter(function(z) { return groupId(z.el) === g; });\r\n    if (!list.length) list = getZoomList();\r\n    idx = Math.max(0, list.findIndex(function(z) { return z.el === el; }));\r\n    render();\r\n    lb.classList.add(\"open\"); lb.setAttribute(\"aria-hidden\", \"false\");\r\n    document.body.style.overflow = \"hidden\";\r\n    if (lenis) lenis.stop();\r\n  }\r\n\r\n  function close() {\r\n    lb.classList.remove(\"open\"); lb.setAttribute(\"aria-hidden\", \"true\");\r\n    document.body.style.overflow = \"\";\r\n    if (lenis) lenis.start();\r\n  }\r\n\r\n  function nav(d) { if (!list.length) return; idx = (idx + d + list.length) % list.length; render(); }\r\n\r\n  document.addEventListener(\"click\", function(e) {\r\n    var z = e.target.closest(\"[data-zoom]\");\r\n    if (!z || suppressClick) return;\r\n    e.preventDefault();\r\n    open(z);\r\n  });\r\n\r\n  $(\"#lbClose\").addEventListener(\"click\", function(e) { e.stopPropagation(); close(); });\r\n  $(\"#lbPrev\").addEventListener(\"click\", function(e) { e.stopPropagation(); nav(-1); });\r\n  $(\"#lbNext\").addEventListener(\"click\", function(e) { e.stopPropagation(); nav(1); });\r\n  lb.addEventListener(\"click\", function(e) { if (!e.target.closest(\".lightbox__img, button, .lightbox__cap\")) close(); });\r\n\r\n  document.addEventListener(\"keydown\", function(e) {\r\n    if (!lb.classList.contains(\"open\")) return;\r\n    if (e.key === \"Escape\") close();\r\n    if (e.key === \"ArrowRight\") nav(1);\r\n    if (e.key === \"ArrowLeft\") nav(-1);\r\n  });\r\n\r\n  var sx = 0;\r\n  lb.addEventListener(\"touchstart\", function(e) { sx = e.touches[0].clientX; }, { passive: true });\r\n  lb.addEventListener(\"touchend\", function(e) { var dx = e.changedTouches[0].clientX - sx; if (Math.abs(dx) > 50) nav(dx < 0 ? 1 : -1); });\r\n\r\n  window.__openZoom = open;\r\n}\r\n","/* Botones magnéticos */\r\nfunction initMagnetic() {\r\n  if (isTouch || reduce) return;\r\n  $$(\"[data-magnetic]\").forEach(function(el) {\r\n    el.addEventListener(\"mousemove\", function(e) {\r\n      var r = el.getBoundingClientRect();\r\n      var x = e.clientX - r.left - r.width / 2;\r\n      var y = e.clientY - r.top - r.height / 2;\r\n      gsap.to(el, { x: x * 0.35, y: y * 0.35, duration: 0.5, ease: \"power3.out\" });\r\n    });\r\n    el.addEventListener(\"mouseleave\", function() {\r\n      gsap.to(el, { x: 0, y: 0, duration: 0.6, ease: \"elastic.out(1,0.4)\" });\r\n    });\r\n  });\r\n}\r\n","/* ── Mapa de Mesas — Casa Pestalozzi ───────────────────────── */\n\nfunction initMapa() {\n  if (initMapa._done) return;\n  initMapa._done = true;\n\n  var canvas = $('#mapa-canvas');\n  if (!canvas) return;\n\n  // ── Estado ────────────────────────────────────────────────\n  var mesas         = [];\n  var reservaciones = [];\n  var tickets       = [];\n  var commandaItems    = []; // { n, p, area, area_id, categoria, comensal, qty }\n  var selectedComensal = 0;  // 0 = General\n  var SUGERENCIAS         = []; // se llenan al abrir cada ticket (ver buildModalContent)\n  var sugComensalesCount  = 0;\n  var sliderMin     = 0;\n  var isLive        = false;\n  var liveInterval  = null;\n  var pollTimer     = null;\n\n  // ── Refs DOM ──────────────────────────────────────────────\n  var slider        = $('#mapa-time-slider');\n  var sliderProg    = $('#mapa-slider-progress');\n  var sliderTip     = $('#mapa-slider-tooltip');\n  var fechaInput    = $('#mapa-fecha');\n  var reservasList  = $('#mapa-reservas-list');\n  var ahoraBtn      = $('#mapa-ahora-btn');\n  var currentTimeEl = $('#mapa-current-time');\n  var liveBadge     = $('#mapa-live-badge');\n  var reservaCount  = $('#mapa-reserva-count');\n  var loadingEl     = $('#mapa-loading');\n  var modal         = $('#mesa-modal');\n  var modalContent  = $('#mesa-modal-content');\n  var modalBd       = $('#mesa-modal-bd');\n  var modalClose    = $('#mesa-modal-close');\n\n  var DURACION = 90;\n  var BLOQUEO  = 30;\n\n  // Labels de estado temporal para el sidebar\n  var TEMPORAL_LABELS = {\n    'vencida':  'Vencida',\n    'en-curso': 'En curso',\n    'proxima':  'Próxima',\n    'cancelada':'Cancelada'\n  };\n\n  // ── Helpers ───────────────────────────────────────────────\n  function minutos(hora) {\n    var p = hora.split(':');\n    return parseInt(p[0], 10) * 60 + parseInt(p[1], 10);\n  }\n\n  function formatTime(min) {\n    var h = Math.floor(min / 60);\n    var m = min % 60;\n    return (h < 10 ? '0' : '') + h + ':' + (m < 10 ? '0' : '') + m;\n  }\n\n  function snapTo30(min) { return Math.round(min / 30) * 30; }\n\n  function mesaPorId(id) {\n    for (var i = 0; i < mesas.length; i++) {\n      if (mesas[i].id === id) return mesas[i];\n    }\n    return null;\n  }\n\n  function escHtml(str) {\n    return String(str)\n      .replace(/&/g, '&amp;')\n      .replace(/</g, '&lt;')\n      .replace(/>/g, '&gt;')\n      .replace(/\"/g, '&quot;');\n  }\n\n  // ── Pool de sugerencias (aleatorio desde el menú, de momento) ──\n  function buildSuggestionPool() {\n    var pool = [];\n    if (!window.CP_MENU) return pool;\n    for (var ci = 0; ci < window.CP_MENU.length; ci++) {\n      var cat = window.CP_MENU[ci];\n      for (var di = 0; di < cat.dishes.length; di++) {\n        var dish     = cat.dishes[di];\n        var areaSlug = dish.area || 'cocina';\n        var areaInfo = window.CP_AREAS ? window.CP_AREAS[areaSlug] : null;\n        pool.push({\n          n: dish.n, p: dish.p, area: areaSlug,\n          area_id: areaInfo ? areaInfo.id : 3,\n          categoria: cat.label,\n          areaNombre: areaInfo ? areaInfo.label : ''\n        });\n      }\n    }\n    return pool;\n  }\n\n  function pickRandomSuggestion(excludeNames) {\n    var pool = buildSuggestionPool().filter(function(s) {\n      return excludeNames.indexOf(s.n) === -1;\n    });\n    if (!pool.length) return null;\n    return pool[Math.floor(Math.random() * pool.length)];\n  }\n\n  // Estado temporal de una reserva respecto al slider\n  function temporalEstadoReserva(r) {\n    if (r.estado === 'cancelada') return 'cancelada';\n    var rMin = minutos(r.hora);\n    if (sliderMin >= rMin + DURACION)                     return 'vencida';\n    if (sliderMin >= rMin && sliderMin < rMin + DURACION) return 'en-curso';\n    if (sliderMin >= rMin - BLOQUEO && sliderMin < rMin)  return 'proxima';\n    return 'futura';\n  }\n\n  // ── Lookups de ticket y reserva ───────────────────────────\n  function isLlevar(mesa) {\n    return mesa && mesa.tipo === 'especial' && mesa.nombre === 'Llevar';\n  }\n\n  function ticketActual(mesaId) {\n    for (var i = 0; i < tickets.length; i++) {\n      var t = tickets[i];\n      if (t.mesa_id === mesaId || t.mesa_secundaria_id === mesaId) return t;\n    }\n    return null;\n  }\n\n  function ticketsParaMesa(mesaId) {\n    var result = [];\n    for (var i = 0; i < tickets.length; i++) {\n      var t = tickets[i];\n      if (t.mesa_id === mesaId || t.mesa_secundaria_id === mesaId) result.push(t);\n    }\n    return result;\n  }\n\n  function reservaParaModal(mesaId) {\n    for (var i = 0; i < reservaciones.length; i++) {\n      var r = reservaciones[i];\n      if (r.estado === 'cancelada') continue;\n      if (r.mesa_id !== mesaId && r.mesa_secundaria_id !== mesaId) continue;\n      return r;\n    }\n    return null;\n  }\n\n  // ── Estado de mesa según slider (incluye tickets abiertos) ─\n  function estadoMesa(mesaId, minActual) {\n    if (ticketActual(mesaId)) return 'con-ticket';\n    var estado = 'libre';\n    for (var i = 0; i < reservaciones.length; i++) {\n      var r = reservaciones[i];\n      if (r.estado === 'cancelada') continue;\n      if (r.mesa_id !== mesaId && r.mesa_secundaria_id !== mesaId) continue;\n      var rMin = minutos(r.hora);\n      var rIni = rMin - BLOQUEO;\n      var rFin = rMin + DURACION;\n      if (minActual >= rMin && minActual < rFin) return 'ocupada';\n      if (minActual >= rIni && minActual < rMin) return 'bloqueada';\n      if (minActual >= rIni - 30 && minActual < rIni && estado === 'libre') estado = 'proxima';\n    }\n    return estado;\n  }\n\n  // Estado con tiempo real (para el modal)\n  function estadoMesaActual(mesaId) {\n    var mesa = mesaPorId(mesaId);\n    if (!isLlevar(mesa) && ticketActual(mesaId)) return 'con-ticket';\n    var now    = new Date();\n    var minNow = now.getHours() * 60 + now.getMinutes();\n    var estado = 'libre';\n    for (var i = 0; i < reservaciones.length; i++) {\n      var r = reservaciones[i];\n      if (r.estado === 'cancelada') continue;\n      if (r.mesa_id !== mesaId && r.mesa_secundaria_id !== mesaId) continue;\n      var rMin = minutos(r.hora);\n      var rIni = rMin - BLOQUEO;\n      var rFin = rMin + DURACION;\n      if (minNow >= rMin && minNow < rFin) return 'ocupada';\n      if (minNow >= rIni && minNow < rMin) return 'bloqueada';\n      if (minNow >= rIni - 30 && minNow < rIni && estado === 'libre') estado = 'proxima';\n    }\n    return estado;\n  }\n\n  // ── Render: estados de todos los pines ────────────────────\n  function renderEstados() {\n    var pins = $$('.mesa-pin[data-id]', canvas);\n    for (var i = 0; i < pins.length; i++) {\n      var pin = pins[i];\n      if (pin.dataset.ticketable !== '1') continue;\n      var id     = parseInt(pin.dataset.id, 10);\n      var estado = estadoMesa(id, sliderMin);\n      pin.classList.remove(\n        'mesa-pin--libre', 'mesa-pin--proxima', 'mesa-pin--bloqueada',\n        'mesa-pin--ocupada', 'mesa-pin--con-ticket'\n      );\n      pin.classList.add('mesa-pin--' + estado);\n      pin.dataset.estado = estado;\n    }\n  }\n\n  // ── Render: pines en el canvas ────────────────────────────\n  function renderMesas() {\n    canvas.innerHTML = '';\n    for (var i = 0; i < mesas.length; i++) {\n      var m   = mesas[i];\n      var ticketable = m.reservable || m.tipo === 'barra'\n                       || (m.tipo === 'especial' && m.nombre !== 'Caja');\n      var pin = document.createElement('div');\n      pin.className = 'mesa-pin mesa-pin--tipo-' + m.tipo;\n      pin.className += m.reservable ? ' mesa-pin--libre' : ' mesa-pin--zona';\n      pin.dataset.id         = m.id;\n      pin.dataset.numero     = m.numero;\n      pin.dataset.reservable = m.reservable;\n      pin.dataset.ticketable = ticketable ? '1' : '0';\n      pin.style.left = m.pos_x + '%';\n      pin.style.top  = m.pos_y + '%';\n      pin.title      = m.nombre + (m.capacidad ? ' · Cap. ' + m.capacidad : '');\n      var label = document.createElement('span');\n      label.className   = 'mesa-pin__label';\n      label.textContent = m.nombre;\n      pin.appendChild(label);\n      if (ticketable) {\n        (function(mesaId) {\n          pin.addEventListener('click', function() { onMesaClick(mesaId); });\n        })(m.id);\n      }\n      canvas.appendChild(pin);\n    }\n  }\n\n  // ── Render: sidebar de reservaciones ──────────────────────\n  function renderSidebar() {\n    if (!reservaciones.length) {\n      reservasList.innerHTML =\n        '<div class=\"mapa-empty-state\">' +\n          '<span class=\"mapa-empty-icon\">◌</span>' +\n          '<span>Sin reservaciones para este día</span>' +\n        '</div>';\n      reservaCount.textContent = '0';\n      return;\n    }\n    reservaCount.textContent = reservaciones.length;\n    reservasList.innerHTML   = '';\n    for (var i = 0; i < reservaciones.length; i++) {\n      var r          = reservaciones[i];\n      var tempEstado = temporalEstadoReserva(r);\n      var card       = document.createElement('div');\n      card.className  = 'reserva-card';\n      card.dataset.id = r.id;\n\n      if (r.estado === 'cancelada')       card.classList.add('reserva-card--pasada');\n      else if (tempEstado === 'vencida')  card.classList.add('reserva-card--pasada');\n      else if (tempEstado === 'en-curso') card.classList.add('reserva-card--activa');\n      else if (tempEstado === 'proxima')  card.classList.add('reserva-card--proxima');\n\n      var mesaNombre = '';\n      if (r.mesa_id) {\n        var m1 = mesaPorId(r.mesa_id);\n        if (m1) mesaNombre = m1.nombre;\n        if (r.mesa_secundaria_id) {\n          var m2 = mesaPorId(r.mesa_secundaria_id);\n          if (m2) mesaNombre += ' + ' + m2.nombre;\n        }\n      }\n\n      var temporalBadge = TEMPORAL_LABELS[tempEstado]\n        ? '<span class=\"reserva-card__temporal reserva-card__temporal--' + tempEstado + '\">' +\n          TEMPORAL_LABELS[tempEstado] + '</span>'\n        : '';\n\n      card.innerHTML =\n        '<div class=\"reserva-card__hora\">' + r.hora.substring(0, 5) + '</div>' +\n        '<div class=\"reserva-card__info\">' +\n          '<span class=\"reserva-card__nombre\">' + escHtml(r.nombre) + '</span>' +\n          '<span class=\"reserva-card__meta\">' +\n            '<span class=\"reserva-card__comensales\">&#x1F465; ' + r.comensales + '</span>' +\n            (mesaNombre ? '<span class=\"reserva-card__mesa\">' + escHtml(mesaNombre) + '</span>' : '') +\n          '</span>' +\n          temporalBadge +\n        '</div>' +\n        '<div class=\"reserva-card__estado reserva-card__estado--' + r.estado + '\">' + r.estado + '</div>';\n\n      (function(rid, mid, mid2) {\n        card.addEventListener('click', function() { onCardClick(rid, mid, mid2); });\n      })(r.id, r.mesa_id, r.mesa_secundaria_id);\n      reservasList.appendChild(card);\n    }\n  }\n\n  // ── Click en canvas / sidebar ─────────────────────────────\n  function clearHighlight() {\n    var pins  = $$('.mesa-pin', canvas);\n    var cards = $$('.reserva-card', reservasList);\n    for (var i = 0; i < pins.length;  i++) pins[i].classList.remove('mesa-pin--highlight');\n    for (var i = 0; i < cards.length; i++) cards[i].classList.remove('reserva-card--selected');\n  }\n\n  function onMesaClick(mesaId) {\n    var mesa = mesaPorId(mesaId);\n    var canOpen = mesa && (mesa.reservable || mesa.tipo === 'barra'\n                  || (mesa.tipo === 'especial' && mesa.nombre !== 'Caja'));\n    if (!canOpen) return;\n    if (isLlevar(mesa)) {\n      showLlevarModal(mesa);\n    } else {\n      showModal(mesa, estadoMesaActual(mesaId));\n    }\n  }\n\n  // ── Modal Llevar ──────────────────────────────────────────\n  function showLlevarModal(mesa) {\n    if (!modal || !modalContent) return;\n    var llevarTickets = ticketsParaMesa(mesa.id);\n    commandaItems    = [];\n    selectedComensal = 0;\n    if (llevarTickets.length === 0) {\n      modalContent.innerHTML = buildModalContent(mesa, 'libre', null, null);\n    } else {\n      modalContent.innerHTML = buildLlevarList(mesa, llevarTickets);\n    }\n    modal.classList.add('mesa-modal--open');\n    document.body.style.overflow = 'hidden';\n    if (llevarTickets.length === 0) {\n      bindModalActions(mesa, null, null);\n    } else {\n      bindLlevarList(mesa, llevarTickets);\n    }\n  }\n\n  function buildLlevarList(mesa, llevarTickets) {\n    var h = '';\n    h += '<div class=\"mmodal-header\"><div class=\"mmodal-header-id\">';\n    h += '<span class=\"mmodal-title\">Pedidos para Llevar</span>';\n    h += '<span class=\"mmodal-llevar-count\">' + llevarTickets.length + ' activos</span>';\n    h += '</div></div>';\n\n    h += '<div class=\"mmodal-llevar-list\">';\n    for (var i = 0; i < llevarTickets.length; i++) {\n      var t = llevarTickets[i];\n      var horaAp = t.hora_apertura ? String(t.hora_apertura).substring(11, 16) : '--:--';\n      var nombreLabel = t.nombre ? escHtml(t.nombre) : '<em style=\"opacity:.55\">Sin nombre</em>';\n      h += '<div class=\"mmodal-llevar-row\" data-tid=\"' + t.id + '\">';\n      h += '<div class=\"mmodal-llevar-row__info\">';\n      h += '<span class=\"mmodal-llevar-row__nombre\">' + nombreLabel + '</span>';\n      h += '<span class=\"mmodal-llevar-row__meta\">🕐 ' + horaAp + ' &nbsp;·&nbsp; 👥 ' + t.comensales + '</span>';\n      h += '</div>';\n      h += '<span class=\"mmodal-llevar-row__arrow\">→</span>';\n      h += '</div>';\n    }\n    h += '</div>';\n\n    h += '<div class=\"mmodal-actions\">';\n    h += '<button class=\"mmodal-btn mmodal-btn--primary\" id=\"mmodal-llevar-nuevo\">+ Nuevo pedido</button>';\n    h += '</div>';\n    return h;\n  }\n\n  function bindLlevarList(mesa, llevarTickets) {\n    var rows = modalContent.querySelectorAll('.mmodal-llevar-row[data-tid]');\n    for (var i = 0; i < rows.length; i++) {\n      (function(row) {\n        row.addEventListener('click', function() {\n          var tid = parseInt(row.dataset.tid, 10);\n          var ticket = null;\n          for (var j = 0; j < llevarTickets.length; j++) {\n            if (llevarTickets[j].id === tid) { ticket = llevarTickets[j]; break; }\n          }\n          if (!ticket) return;\n          commandaItems    = [];\n          selectedComensal = 0;\n          modalContent.innerHTML = buildModalContent(mesa, 'con-ticket', null, ticket);\n          bindModalActions(mesa, null, ticket);\n        });\n      })(rows[i]);\n    }\n\n    var nuevoBtn = modalContent.querySelector('#mmodal-llevar-nuevo');\n    if (nuevoBtn) {\n      nuevoBtn.addEventListener('click', function() {\n        commandaItems    = [];\n        selectedComensal = 0;\n        modalContent.innerHTML = buildModalContent(mesa, 'libre', null, null);\n        bindModalActions(mesa, null, null);\n      });\n    }\n  }\n\n  function onCardClick(reservaId, mesaId, mesa2Id) {\n    clearHighlight();\n    highlightReserva(reservaId, mesaId, mesa2Id);\n  }\n\n  function highlightReserva(reservaId, mesaId, mesa2Id) {\n    var card = reservasList.querySelector('[data-id=\"' + reservaId + '\"]');\n    if (card) {\n      card.classList.add('reserva-card--selected');\n      card.scrollIntoView({ behavior: 'smooth', block: 'nearest' });\n    }\n    if (mesaId) {\n      var pin = canvas.querySelector('[data-id=\"' + mesaId + '\"]');\n      if (pin) pin.classList.add('mesa-pin--highlight');\n    }\n    if (mesa2Id) {\n      var pin2 = canvas.querySelector('[data-id=\"' + mesa2Id + '\"]');\n      if (pin2) pin2.classList.add('mesa-pin--highlight');\n    }\n  }\n\n  // ── Modal ─────────────────────────────────────────────────\n  function showModal(mesa, estado) {\n    if (!modal || !modalContent) return;\n    commandaItems    = [];\n    selectedComensal = 0;\n    var reserva = reservaParaModal(mesa.id);\n    var ticket  = ticketActual(mesa.id);\n    modalContent.innerHTML = buildModalContent(mesa, estado, reserva, ticket);\n    modal.classList.add('mesa-modal--open');\n    document.body.style.overflow = 'hidden';\n    bindModalActions(mesa, reserva, ticket);\n  }\n\n  function closeModal() {\n    if (!modal) return;\n    modal.classList.remove('mesa-modal--open');\n    document.body.style.overflow = '';\n  }\n\n  function buildModalContent(mesa, estado, reserva, ticket) {\n    var h = '';\n\n    // Header: nombre de mesa + nombre del cliente agrupados a la izquierda\n    h += '<div class=\"mmodal-header\"><div class=\"mmodal-header-id\">';\n    h += '<span class=\"mmodal-title\">' + escHtml(mesa.nombre) + '</span>';\n    if (ticket && ticket.nombre) {\n      h += '<span class=\"mmodal-title-cliente\">— ' + escHtml(ticket.nombre) + '</span>';\n    }\n    h += '</div></div>';\n\n    if (estado === 'con-ticket' && ticket) {\n      // ── Vista de ticket abierto con sistema de comandas ────\n\n      // Poblar sugerencias aleatorias (2 ítems) para este ticket\n      sugComensalesCount = ticket.comensales;\n      SUGERENCIAS = [];\n      var sugUsed = [];\n      var sgPick = pickRandomSuggestion(sugUsed);\n      if (sgPick) { SUGERENCIAS.push(sgPick); }\n\n      var horaAp = ticket.hora_apertura\n        ? String(ticket.hora_apertura).substring(11, 16)\n        : '--:--';\n\n      h += '<div class=\"mmodal-ticket-meta\">';\n      h += '<span>👥 ' + ticket.comensales + ' com.</span>';\n      h += '<span>🕐 ' + horaAp + '</span>';\n      h += '</div>';\n\n      // Tabs principales (mobile: 3 tabs; desktop: ocultos)\n      h += '<div class=\"mmodal-tabs\" id=\"mmodal-tabs\">';\n      h += '<button class=\"mmodal-tab mmodal-tab--active\" data-tab=\"menu\">Menú</button>';\n      h += '<button class=\"mmodal-tab\" data-tab=\"cart\">Pedido';\n      h += ' <span class=\"mmodal-tab-badge\" id=\"mmodal-cart-badge\" style=\"display:none\">0</span>';\n      h += '</button>';\n      h += '<button class=\"mmodal-tab\" data-tab=\"resumen\">Ticket';\n      h += ' <span class=\"mmodal-tab-badge\" id=\"mmodal-resumen-badge\" style=\"display:none\">0</span>';\n      h += '</button>';\n      h += '<button class=\"mmodal-tab\" data-tab=\"sugerencias\">Sugerencias</button>';\n      h += '</div>';\n\n      // ── Panels wrapper (3 cols en desktop) ────────────────\n      h += '<div class=\"mmodal-panels\">';\n\n      // ── Panel 1: Menú ──────────────────────────────────────\n      h += '<div id=\"mmodal-panel-menu\" class=\"mmodal-tab-panel mmodal-tab-panel--active\">';\n      h += '<div class=\"mmodal-panel-label\">Menú</div>';\n      h += '<div class=\"mmodal-panel-scroll\">';\n\n      // Bloques de comensal (grid)\n      h += '<div class=\"mmodal-section-label\">Comensal</div>';\n      h += '<div class=\"mmodal-comensal-grid\" id=\"mmodal-comensales\">';\n      h += '<button class=\"mmodal-comensal-block mmodal-comensal-block--active\" data-c=\"0\">Gral</button>';\n      for (var ci = 1; ci <= ticket.comensales; ci++) {\n        h += '<button class=\"mmodal-comensal-block\" data-c=\"' + ci + '\">C.' + ci + '</button>';\n      }\n      h += '</div>';\n\n      // Bloques de categoría (grid)\n      h += '<div class=\"mmodal-section-label\">Categoría</div>';\n      h += '<div class=\"mmodal-cat-grid\" id=\"mmodal-cats\">';\n      if (window.CP_MENU && window.CP_MENU.length) {\n        for (var mi = 0; mi < window.CP_MENU.length; mi++) {\n          var mcat = window.CP_MENU[mi];\n          h += '<button class=\"mmodal-cat-block' + (mi === 0 ? ' mmodal-cat-block--active' : '') +\n               '\" data-idx=\"' + mi + '\">' + escHtml(mcat.label) + '</button>';\n        }\n      }\n      h += '</div>';\n      h += '<div class=\"mmodal-dishes\" id=\"mmodal-dishes\"></div>';\n\n      h += '</div>'; // fin panel-scroll\n      h += '</div>'; // fin panel-menu\n\n      // ── Panel 2: Pedido (carrito staging) ─────────────────\n      h += '<div id=\"mmodal-panel-cart\" class=\"mmodal-tab-panel\">';\n      h += '<div class=\"mmodal-panel-label\">Pedido</div>';\n      h += '<div class=\"mmodal-panel-scroll\">';\n      h += '<div class=\"mmodal-cart\" id=\"mmodal-cart\">';\n      h += '<div class=\"mmodal-col-empty\"><span class=\"mmodal-col-empty__icon\">☰</span>' +\n           '<span>Selecciona platos en el Menú</span></div>';\n      h += '</div>';\n      h += '</div>'; // fin panel-scroll\n      h += '<div class=\"mmodal-panel-actions\">';\n      h += '<div class=\"mmodal-total-row\" id=\"mmodal-cart-total\" style=\"display:none\">';\n      h += '<span class=\"mmodal-total-label\">Total</span>';\n      h += '<span class=\"mmodal-total-amount\" id=\"mmodal-total-val\">$0</span>';\n      h += '</div>';\n      h += '<button class=\"mmodal-btn mmodal-btn--primary\" id=\"mmodal-enviar\" disabled>';\n      h += 'Confirmar y enviar (0) →';\n      h += '</button>';\n      h += '</div>'; // fin panel-actions\n      h += '</div>'; // fin panel-cart\n\n      // ── Panel 3: Estado del ticket ─────────────────────────\n      h += '<div id=\"mmodal-panel-resumen\" class=\"mmodal-tab-panel\">';\n      h += '<div class=\"mmodal-panel-label\">Estado del ticket</div>';\n      h += '<div class=\"mmodal-panel-scroll\">';\n      h += '<div id=\"mmodal-resumen-content\">';\n      h += '<div class=\"mmodal-col-empty\"><span class=\"mmodal-col-empty__icon\">◎</span>' +\n           '<span>Sin comandas enviadas aún</span></div>';\n      h += '</div>';\n      h += '</div>'; // fin panel-scroll\n      h += '<div class=\"mmodal-panel-actions\">';\n      h += '<button class=\"mmodal-btn mmodal-btn--danger\" id=\"mmodal-cerrar\">Cerrar ticket</button>';\n      h += '</div>'; // fin panel-actions\n      h += '</div>'; // fin panel-resumen\n\n      // ── Panel 4: Sugerencias ─────────────────────────────────\n      h += '<div id=\"mmodal-panel-sugerencias\" class=\"mmodal-tab-panel\">';\n      h += '<div class=\"mmodal-panel-label\">Sugerencias</div>';\n      h += '<div class=\"mmodal-panel-scroll\" id=\"mmodal-sug-list\">';\n      for (var si = 0; si < SUGERENCIAS.length; si++) {\n        h += buildSuggestionCardHtml(si, SUGERENCIAS[si]);\n      }\n      h += '</div>'; // fin panel-scroll\n      h += '</div>'; // fin panel-sugerencias\n\n      h += '</div>'; // fin mmodal-panels\n\n    } else if (reserva) {\n      // ── Vista de reservación activa ────────────────────────\n      var chipLabel = estado === 'bloqueada' ? '¡Próxima a llegar!'\n        : estado === 'ocupada'              ? 'En ventana de reserva'\n        : estado === 'proxima'              ? 'Próxima reservación'\n        : 'Mesa reservada';\n\n      h += '<div class=\"mmodal-reserva-grid\">';\n\n      // Col 1 — cliente\n      h += '<div class=\"mmodal-reserva-col\">';\n      h += '<div class=\"mmodal-reserva-col-head\">';\n      h += '<span class=\"mmodal-reserva-col__label\">Cliente</span>';\n      h += '<span class=\"mmodal-chip mmodal-chip--' + estado + '\">' + chipLabel + '</span>';\n      h += '</div>';\n      h += '<div class=\"mmodal-reserva-nombre\">' + escHtml(reserva.nombre) + '</div>';\n      h += '</div>';\n\n      // Col 2 — detalles\n      h += '<div class=\"mmodal-reserva-col\">';\n      h += '<span class=\"mmodal-reserva-col__label\">Reservación</span>';\n      h += '<div class=\"mmodal-reserva-stats\">';\n      h += '<div class=\"mmodal-reserva-stat mmodal-reserva-stat--hora\"><span class=\"mmodal-reserva-stat__label\">Hora</span>' +\n           '<span class=\"mmodal-reserva-stat__val\">' + reserva.hora.substring(0, 5) + '</span></div>';\n      h += '<div class=\"mmodal-reserva-stat mmodal-reserva-stat--pax\"><span class=\"mmodal-reserva-stat__label\">Comensales</span>' +\n           '<span class=\"mmodal-reserva-stat__val\">' + reserva.comensales + '</span></div>';\n      h += '</div>';\n      if (reserva.nota) {\n        h += '<div class=\"mmodal-reserva-nota\"><span class=\"mmodal-reserva-nota__label\">Nota</span>' + escHtml(reserva.nota) + '</div>';\n      }\n      h += '</div>';\n\n      // Col 3 — acciones\n      h += '<div class=\"mmodal-reserva-col mmodal-reserva-col--actions\">';\n      h += '<span class=\"mmodal-reserva-col__label\">Acción</span>';\n      h += '<button class=\"mmodal-btn mmodal-btn--primary\" id=\"mmodal-confirmar\">✓ Confirmar llegada</button>';\n      h += '<button class=\"mmodal-btn mmodal-btn--ghost\" id=\"mmodal-liberar\">Liberar mesa</button>';\n      h += '</div>';\n\n      h += '</div>';\n\n    } else {\n      // ── Vista de mesa libre: abrir ticket ─────────────────\n      var defaultCom = isLlevar(mesa) ? 1 : 2;\n      h += '<div class=\"mmodal-name-wrap\">';\n      h += '<div class=\"mmodal-label\">Nombre</div>';\n      h += '<input type=\"text\" class=\"mmodal-name-input\" id=\"mmodal-nombre\"';\n      h += ' placeholder=\"Nombre del comensal\" autocomplete=\"off\" maxlength=\"80\">';\n      h += '</div>';\n      h += '<div class=\"mmodal-stepper-wrap\">';\n      h += '<div class=\"mmodal-label\">Comensales</div>';\n      h += '<div class=\"mmodal-stepper\">';\n      h += '<button class=\"mmodal-step\" id=\"mmodal-dec\">−</button>';\n      h += '<span class=\"mmodal-step-val\" id=\"mmodal-cval\">' + defaultCom + '</span>';\n      h += '<button class=\"mmodal-step\" id=\"mmodal-inc\">+</button>';\n      h += '</div>';\n      h += '</div>';\n      h += '<div class=\"mmodal-actions\">';\n      h += '<button class=\"mmodal-btn mmodal-btn--primary\" id=\"mmodal-abrir\">Abrir ticket</button>';\n      h += '</div>';\n    }\n\n    return h;\n  }\n\n  // ── Sistema de productos en ticket ────────────────────────\n  function renderCategoryDishes(cat) {\n    var dishesEl = modalContent.querySelector('#mmodal-dishes');\n    if (!dishesEl || !cat || !cat.dishes) return;\n    dishesEl.innerHTML = '';\n    for (var i = 0; i < cat.dishes.length; i++) {\n      var dish     = cat.dishes[i];\n      var areaInfo = (window.CP_AREAS && dish.area) ? window.CP_AREAS[dish.area] : null;\n      var row      = document.createElement('div');\n      row.className = 'mmodal-dish-row';\n\n      var areaHtml = '';\n      if (areaInfo) {\n        areaHtml = '<span class=\"mmodal-area-badge\" style=\"background:' + areaInfo.color + '22;' +\n                   'color:' + areaInfo.color + ';border-color:' + areaInfo.color + '55\">' +\n                   escHtml(areaInfo.label) + '</span>';\n      }\n\n      row.innerHTML =\n        '<div class=\"mmodal-dish-info\">' +\n          '<span class=\"mmodal-dish-name\">' + escHtml(dish.n) + '</span>' +\n          areaHtml +\n        '</div>' +\n        '<span class=\"mmodal-dish-price\">$' + dish.p + '</span>';\n\n      var addBtn = document.createElement('button');\n      addBtn.className   = 'mmodal-dish-add';\n      addBtn.textContent = '+';\n      addBtn.setAttribute('aria-label', 'Agregar ' + dish.n);\n      (function(d, catLabel) {\n        addBtn.addEventListener('click', function() {\n          addToComanda(d.n, d.p, d.area || 'cocina', catLabel);\n        });\n      })(dish, cat.label);\n      row.appendChild(addBtn);\n      dishesEl.appendChild(row);\n    }\n  }\n\n  function addToComanda(name, price, areaSlug, categoria) {\n    var areaId = (window.CP_AREAS && window.CP_AREAS[areaSlug])\n                 ? window.CP_AREAS[areaSlug].id : 3;\n    var found = false;\n    for (var i = 0; i < commandaItems.length; i++) {\n      var ci = commandaItems[i];\n      if (ci.n === name && ci.comensal === selectedComensal) {\n        ci.qty++;\n        found = true;\n        break;\n      }\n    }\n    if (!found) {\n      commandaItems.push({\n        n: name, p: price, area: areaSlug, area_id: areaId,\n        categoria: categoria, comensal: selectedComensal, qty: 1, nota: ''\n      });\n    }\n    renderComandaCart();\n    updateEnviarBtn();\n  }\n\n  function addSuggestionItem(sug, comensal) {\n    for (var i = 0; i < commandaItems.length; i++) {\n      if (commandaItems[i].n === sug.n && commandaItems[i].comensal === comensal) {\n        commandaItems[i].qty++;\n        renderComandaCart();\n        return;\n      }\n    }\n    commandaItems.push({\n      n: sug.n, p: sug.p, area: sug.area, area_id: sug.area_id,\n      categoria: sug.categoria, comensal: comensal, qty: 1, nota: ''\n    });\n    renderComandaCart();\n  }\n\n  function removeSuggestionItem(nombre, comensal) {\n    for (var i = 0; i < commandaItems.length; i++) {\n      if (commandaItems[i].n === nombre && commandaItems[i].comensal === comensal) {\n        commandaItems.splice(i, 1);\n        renderComandaCart();\n        return;\n      }\n    }\n  }\n\n  function buildSuggestionCardHtml(idx, sug) {\n    var h = '<div class=\"mmodal-sug-card\" data-sug-card=\"' + idx + '\">';\n    h += '<div class=\"mmodal-sug-header\">';\n    h += '<span class=\"mmodal-sug-name\">' + escHtml(sug.n) + '</span>';\n    h += '<span class=\"mmodal-sug-price\">$' + sug.p + '</span>';\n    h += '</div>';\n    h += '<div class=\"mmodal-sug-area\">' + escHtml(sug.areaNombre) + '</div>';\n    h += '<div class=\"mmodal-sug-divider\"></div>';\n    h += '<div class=\"mmodal-sug-question\">¿Quién acepta?</div>';\n    h += '<div class=\"mmodal-sug-chips\">';\n    h += '<button class=\"mmodal-sug-chip\" data-sug=\"' + idx + '\" data-c=\"0\">Gral</button>';\n    for (var sc = 1; sc <= sugComensalesCount; sc++) {\n      h += '<button class=\"mmodal-sug-chip\" data-sug=\"' + idx + '\" data-c=\"' + sc + '\">C.' + sc + '</button>';\n    }\n    h += '</div>';\n    h += '<div class=\"mmodal-sug-footer\">';\n    h += '<button class=\"mmodal-sug-swap\" data-swap=\"' + idx + '\">↻ Otra sugerencia</button>';\n    h += '</div>';\n    h += '</div>';\n    return h;\n  }\n\n  function swapSuggestion(idx) {\n    var oldSug = SUGERENCIAS[idx];\n    // Limpiar del carrito si se había aceptado antes\n    for (var i = commandaItems.length - 1; i >= 0; i--) {\n      if (commandaItems[i].n === oldSug.n) commandaItems.splice(i, 1);\n    }\n    var used  = SUGERENCIAS.map(function(s) { return s.n; });\n    var nueva = pickRandomSuggestion(used);\n    if (!nueva) return;\n    SUGERENCIAS[idx] = nueva;\n\n    var card = modalContent && modalContent.querySelector('.mmodal-sug-card[data-sug-card=\"' + idx + '\"]');\n    if (card) {\n      var tmp = document.createElement('div');\n      tmp.innerHTML = buildSuggestionCardHtml(idx, nueva);\n      card.parentNode.replaceChild(tmp.firstChild, card);\n      bindSuggestionCard(idx);\n    }\n    renderComandaCart();\n    updateEnviarBtn();\n  }\n\n  function bindSuggestionCard(idx) {\n    var card = modalContent && modalContent.querySelector('.mmodal-sug-card[data-sug-card=\"' + idx + '\"]');\n    if (!card) return;\n\n    var chips = card.querySelectorAll('.mmodal-sug-chip');\n    for (var c = 0; c < chips.length; c++) {\n      (function(chip) {\n        chip.addEventListener('click', function() {\n          var isOn     = chip.classList.contains('mmodal-sug-chip--on');\n          var comensal = parseInt(chip.dataset.c, 10);\n          var sug      = SUGERENCIAS[idx];\n          if (isOn) {\n            chip.classList.remove('mmodal-sug-chip--on');\n            removeSuggestionItem(sug.n, comensal);\n          } else {\n            chip.classList.add('mmodal-sug-chip--on');\n            addSuggestionItem(sug, comensal);\n          }\n          updateEnviarBtn();\n        });\n      })(chips[c]);\n    }\n\n    var swapBtn = card.querySelector('.mmodal-sug-swap');\n    if (swapBtn) {\n      (function(btn) {\n        btn.addEventListener('click', function() {\n          swapSuggestion(idx);\n        });\n      })(swapBtn);\n    }\n  }\n\n  function renderComandaCart() {\n    var cartEl = modalContent.querySelector('#mmodal-cart');\n    if (!cartEl) return;\n\n    if (!commandaItems.length) {\n      cartEl.innerHTML = '<div class=\"mmodal-cart-empty\">Sin productos</div>';\n      return;\n    }\n\n    cartEl.innerHTML = '';\n    for (var i = 0; i < commandaItems.length; i++) {\n      (function(item, idx) {\n        var comLabel = item.comensal === 0 ? 'G' : 'C.' + item.comensal;\n        var row = document.createElement('div');\n        row.className = 'mmodal-cart-row';\n        row.innerHTML =\n          '<span class=\"mmodal-cart-name\">' + escHtml(item.n) + '</span>' +\n          '<span class=\"mmodal-cart-comensal\">' + comLabel + '</span>' +\n          '<div class=\"mmodal-cart-controls\">' +\n            '<button data-idx=\"' + idx + '\" data-op=\"dec\">−</button>' +\n            '<span>' + item.qty + '</span>' +\n            '<button data-idx=\"' + idx + '\" data-op=\"inc\">+</button>' +\n          '</div>' +\n          '<span class=\"mmodal-cart-subtotal\">$' + (item.p * item.qty) + '</span>';\n\n        // Nota toggle\n        var noteToggle = document.createElement('button');\n        noteToggle.className = 'mmodal-cart-nota-btn' + (item.nota ? ' mmodal-cart-nota-btn--active' : '');\n        noteToggle.type = 'button';\n        noteToggle.textContent = item.nota ? '✎ Nota ✓' : '✎ Nota';\n        row.appendChild(noteToggle);\n\n        var noteWrap = document.createElement('div');\n        noteWrap.className = 'mmodal-cart-nota-wrap';\n        if (!item.nota) noteWrap.style.display = 'none';\n        var noteTA = document.createElement('textarea');\n        noteTA.className = 'mmodal-cart-nota-input';\n        noteTA.placeholder = 'Ej: sin cebolla, término medio…';\n        noteTA.maxLength = 280;\n        noteTA.rows = 2;\n        noteTA.value = item.nota || '';\n        (function(capturedIdx, ta, toggle) {\n          ta.addEventListener('input', function() { commandaItems[capturedIdx].nota = ta.value; });\n          toggle.addEventListener('click', function() {\n            var open = noteWrap.style.display !== 'none';\n            noteWrap.style.display = open ? 'none' : 'block';\n            toggle.textContent = !open ? '✎ Nota ↑' : (commandaItems[capturedIdx].nota ? '✎ Nota ✓' : '✎ Nota');\n          });\n        })(idx, noteTA, noteToggle);\n        noteWrap.appendChild(noteTA);\n        row.appendChild(noteWrap);\n\n        cartEl.appendChild(row);\n      })(commandaItems[i], i);\n    }\n\n    // Rebind +/- en carrito\n    var ctrlBtns = cartEl.querySelectorAll('button[data-op]');\n    for (var j = 0; j < ctrlBtns.length; j++) {\n      (function(btn) {\n        btn.addEventListener('click', function() {\n          var idx = parseInt(btn.dataset.idx, 10);\n          if (btn.dataset.op === 'dec') {\n            if (commandaItems[idx].qty > 1) commandaItems[idx].qty--;\n            else commandaItems.splice(idx, 1);\n          } else {\n            commandaItems[idx].qty++;\n          }\n          renderComandaCart();\n          updateEnviarBtn();\n        });\n      })(ctrlBtns[j]);\n    }\n  }\n\n  function updateEnviarBtn() {\n    var btn      = modalContent.querySelector('#mmodal-enviar');\n    var badge    = modalContent.querySelector('#mmodal-cart-badge');\n    var totalRow = modalContent.querySelector('#mmodal-cart-total');\n    var totalVal = modalContent.querySelector('#mmodal-total-val');\n    var total = 0, amount = 0;\n    for (var i = 0; i < commandaItems.length; i++) {\n      total  += commandaItems[i].qty;\n      amount += commandaItems[i].p * commandaItems[i].qty;\n    }\n    if (btn) {\n      btn.textContent = 'Confirmar y enviar (' + total + ') →';\n      btn.disabled    = (total === 0);\n    }\n    if (badge) { badge.textContent = total; badge.style.display = total > 0 ? 'inline' : 'none'; }\n    if (totalRow) totalRow.style.display = total > 0 ? 'flex' : 'none';\n    if (totalVal) totalVal.textContent = '$' + amount;\n  }\n\n  function renderResumen(ticketId) {\n    var resumenEl = modalContent.querySelector('#mmodal-resumen-content');\n    if (!resumenEl) return;\n    resumenEl.innerHTML = '<div class=\"mmodal-cart-empty\">Cargando…</div>';\n\n    fetch('/api/ticket-items?ticket_id=' + ticketId)\n      .then(function(r) { return r.json(); })\n      .then(function(data) {\n        if (!data.ok || !data.items || !data.items.length) {\n          resumenEl.innerHTML = '<div class=\"mmodal-col-empty\"><span class=\"mmodal-col-empty__icon\">◎</span><span>Sin comandas enviadas aún</span></div>';\n          var badge = modalContent.querySelector('#mmodal-resumen-badge');\n          if (badge) { badge.textContent = '0'; badge.style.display = 'none'; }\n          return;\n        }\n\n        // Agrupar por área\n        var byArea     = {};\n        var grandTotal = 0;\n        for (var i = 0; i < data.items.length; i++) {\n          var it  = data.items[i];\n          var key = it.area_slug;\n          if (!byArea[key]) {\n            byArea[key] = { label: it.area_nombre, color: it.area_color, items: [] };\n          }\n          byArea[key].items.push(it);\n          if (it.estado !== 'cancelado') grandTotal += it.precio * it.cantidad;\n        }\n\n        var html = '';\n        for (var slug in byArea) {\n          if (!byArea.hasOwnProperty(slug)) continue;\n          var ag = byArea[slug];\n          html += '<div class=\"mmodal-confirm-area-header\" style=\"border-left-color:' + ag.color + '\">' +\n                  escHtml(ag.label) + '</div>';\n          for (var j = 0; j < ag.items.length; j++) {\n            var row = ag.items[j];\n            var statusColor = row.estado === 'cancelado'      ? '#555'\n                            : row.estado === 'entregado'      ? '#5ba4cf'\n                            : row.estado === 'listo'          ? '#8bbf7e'\n                            : row.estado === 'en_preparacion' ? '#e8a920' : '#9a9a9a';\n            var statusLabel = row.estado === 'cancelado'      ? 'Cancelado'\n                            : row.estado === 'entregado'      ? 'Entregado ✓'\n                            : row.estado === 'listo'          ? 'Listo'\n                            : row.estado === 'en_preparacion' ? 'En preparación' : 'Enviado';\n            var com = row.comensal !== null ? 'C.' + row.comensal : 'Gral';\n            var entBtn = row.estado === 'listo'\n              ? '<button class=\"mmodal-entregar-btn\" data-id=\"' + row.id + '\">✓ Entregar</button>'\n              : '';\n            var cancelBtn = (row.estado !== 'entregado' && row.estado !== 'cancelado')\n              ? '<button class=\"mmodal-cancel-btn\" data-id=\"' + row.id +\n                '\" data-nombre=\"' + escHtml(row.nombre) + '\">×</button>'\n              : '';\n            var notaHtml = row.nota\n              ? '<span class=\"mmodal-resumen-nota\">' + escHtml(row.nota) + '</span>'\n              : '';\n            var itemClass = row.estado === 'cancelado'\n              ? 'mmodal-confirm-item mmodal-confirm-item--cancelado'\n              : 'mmodal-confirm-item';\n            html += '<div class=\"' + itemClass + '\">' +\n                    '<span class=\"mmodal-status-dot\" style=\"background:' + statusColor + '\" title=\"' + statusLabel + '\"></span>' +\n                    '<span class=\"mmodal-confirm-item-name\">' + escHtml(row.nombre) +\n                    ' <span class=\"mmodal-cart-comensal\">' + com + '</span>' +\n                    notaHtml + '</span>' +\n                    '<span class=\"mmodal-confirm-item-qty\">\\xD7' + row.cantidad + '</span>' +\n                    '<span class=\"mmodal-confirm-item-price\">$' + Math.round(row.precio * row.cantidad) + '</span>' +\n                    cancelBtn + entBtn +\n                    '</div>';\n          }\n        }\n\n        html += '<div class=\"mmodal-total-row\" style=\"margin-top:.6rem\">' +\n                '<span class=\"mmodal-total-label\">Acumulado</span>' +\n                '<span class=\"mmodal-total-amount\">$' + grandTotal + '</span>' +\n                '</div>';\n\n        resumenEl.innerHTML = html;\n\n        // Bind botones \"Entregar\"\n        var entBtns = resumenEl.querySelectorAll('.mmodal-entregar-btn');\n        for (var eb = 0; eb < entBtns.length; eb++) {\n          (function(btn) {\n            btn.addEventListener('click', function() {\n              apiEntregarItem(parseInt(btn.dataset.id, 10), ticketId);\n            });\n          })(entBtns[eb]);\n        }\n\n        // Bind botones \"× Cancelar\"\n        var cancelBtns = resumenEl.querySelectorAll('.mmodal-cancel-btn');\n        for (var cb = 0; cb < cancelBtns.length; cb++) {\n          (function(btn) {\n            btn.addEventListener('click', function() {\n              showCancelItemConfirm(parseInt(btn.dataset.id, 10), btn.dataset.nombre, ticketId);\n            });\n          })(cancelBtns[cb]);\n        }\n\n        // Actualizar badge en tab\n        var badge = modalContent.querySelector('#mmodal-resumen-badge');\n        if (badge) {\n          var activeCount = data.items.filter(function(x) { return x.estado !== 'cancelado'; }).length;\n          badge.textContent   = activeCount;\n          badge.style.display = 'inline';\n        }\n      })\n      .catch(function() {\n        resumenEl.innerHTML = '<div class=\"mmodal-cart-empty mmodal-empty--error\">Error al cargar</div>';\n      });\n  }\n\n  function bindTabsAndComanda(mesa, ticket) {\n    // Bloques de categoría (grid)\n    var catTabs = modalContent.querySelectorAll('.mmodal-cat-block');\n    if (catTabs.length && window.CP_MENU && window.CP_MENU.length) {\n      renderCategoryDishes(window.CP_MENU[0]);\n      for (var i = 0; i < catTabs.length; i++) {\n        (function(tab) {\n          tab.addEventListener('click', function() {\n            for (var k = 0; k < catTabs.length; k++) catTabs[k].classList.remove('mmodal-cat-block--active');\n            tab.classList.add('mmodal-cat-block--active');\n            renderCategoryDishes(window.CP_MENU[parseInt(tab.dataset.idx, 10)]);\n          });\n        })(catTabs[i]);\n      }\n    }\n\n    // Bloques de comensal (grid)\n    var chips = modalContent.querySelectorAll('.mmodal-comensal-block');\n    for (var ci = 0; ci < chips.length; ci++) {\n      (function(chip) {\n        chip.addEventListener('click', function() {\n          for (var k = 0; k < chips.length; k++) chips[k].classList.remove('mmodal-comensal-block--active');\n          chip.classList.add('mmodal-comensal-block--active');\n          selectedComensal = parseInt(chip.dataset.c, 10);\n        });\n      })(chips[ci]);\n    }\n\n    // Tabs principales: Menú / Pedido / Ticket / Sugerencias\n    var mainTabs          = modalContent.querySelectorAll('.mmodal-tab');\n    var panelMenu         = modalContent.querySelector('#mmodal-panel-menu');\n    var panelCart         = modalContent.querySelector('#mmodal-panel-cart');\n    var panelResumen      = modalContent.querySelector('#mmodal-panel-resumen');\n    var panelSugerencias  = modalContent.querySelector('#mmodal-panel-sugerencias');\n    var allPanels         = [panelMenu, panelCart, panelResumen, panelSugerencias];\n\n    function activatePanel(targetTab) {\n      for (var k = 0; k < mainTabs.length; k++) mainTabs[k].classList.remove('mmodal-tab--active');\n      targetTab.classList.add('mmodal-tab--active');\n      for (var p = 0; p < allPanels.length; p++) {\n        if (allPanels[p]) allPanels[p].classList.remove('mmodal-tab-panel--active');\n      }\n      var panel = null;\n      if (targetTab.dataset.tab === 'menu')         panel = panelMenu;\n      if (targetTab.dataset.tab === 'cart')         panel = panelCart;\n      if (targetTab.dataset.tab === 'resumen')      { panel = panelResumen; renderResumen(ticket.id); }\n      if (targetTab.dataset.tab === 'sugerencias')  panel = panelSugerencias;\n      if (panel) panel.classList.add('mmodal-tab-panel--active');\n    }\n\n    for (var ti = 0; ti < mainTabs.length; ti++) {\n      (function(tab) {\n        tab.addEventListener('click', function() { activatePanel(tab); });\n      })(mainTabs[ti]);\n    }\n\n    // Botón \"Confirmar y enviar\" → envío directo (col 2 ya es el preview)\n    var enviarBtn = modalContent.querySelector('#mmodal-enviar');\n    if (enviarBtn) {\n      (function(tid) {\n        enviarBtn.addEventListener('click', function() {\n          if (commandaItems.length === 0) return;\n          apiEnviarComanda(tid);\n        });\n      })(ticket.id);\n    }\n\n    // En desktop las 4 columnas son visibles desde el inicio\n    if (window.innerWidth >= 768) {\n      renderResumen(ticket.id);\n    }\n\n    // Sugerencias: bind inicial de todas las cards\n    for (var sgIdx = 0; sgIdx < SUGERENCIAS.length; sgIdx++) {\n      bindSuggestionCard(sgIdx);\n    }\n  }\n\n  // ── Bind de acciones del modal ────────────────────────────\n  function bindModalActions(mesa, reserva, ticket) {\n    var decBtn = modalContent.querySelector('#mmodal-dec');\n    var incBtn = modalContent.querySelector('#mmodal-inc');\n    var cval   = modalContent.querySelector('#mmodal-cval');\n\n    if (decBtn && cval) {\n      decBtn.addEventListener('click', function() {\n        var v = parseInt(cval.textContent, 10);\n        if (v > 1) cval.textContent = v - 1;\n      });\n    }\n    if (incBtn && cval) {\n      incBtn.addEventListener('click', function() {\n        cval.textContent = parseInt(cval.textContent, 10) + 1;\n      });\n    }\n\n    var abrirBtn = modalContent.querySelector('#mmodal-abrir');\n    if (abrirBtn) {\n      abrirBtn.addEventListener('click', function() {\n        var comensales = cval ? parseInt(cval.textContent, 10) : 2;\n        var nombreEl   = modalContent.querySelector('#mmodal-nombre');\n        var nombre     = nombreEl ? nombreEl.value.trim() : '';\n        if (isLlevar(mesa)) {\n          apiAbrirLlevarTicket(mesa, comensales, nombre || null);\n        } else {\n          apiAbrirTicket(mesa.id, null, comensales, null, nombre || null);\n        }\n      });\n    }\n\n    var confirmarBtn = modalContent.querySelector('#mmodal-confirmar');\n    if (confirmarBtn && reserva) {\n      confirmarBtn.addEventListener('click', function() {\n        apiAbrirTicket(mesa.id, reserva.mesa_secundaria_id, reserva.comensales, reserva.id, reserva.nombre || null);\n      });\n    }\n\n    var liberarBtn = modalContent.querySelector('#mmodal-liberar');\n    if (liberarBtn && reserva) {\n      liberarBtn.addEventListener('click', function() {\n        if (confirm('¿Cancelar la reservación de ' + reserva.nombre + '?')) {\n          apiLiberarReservacion(reserva.id);\n        }\n      });\n    }\n\n    var cerrarBtn = modalContent.querySelector('#mmodal-cerrar');\n    if (cerrarBtn && ticket) {\n      cerrarBtn.addEventListener('click', function() {\n        showCerrarConfirm(mesa, ticket);\n      });\n    }\n\n    // Si hay bloques de categoría (modal de ticket con productos)\n    if (modalContent.querySelector('#mmodal-cats')) {\n      bindTabsAndComanda(mesa, ticket);\n    }\n  }\n\n  // ── Confirmación estilizada de cierre ────────────────────\n  function buildCerrarHeader(mesa, ticket) {\n    var h = '<div class=\"mmodal-header\"><div class=\"mmodal-header-id\">';\n    h += '<span class=\"mmodal-title\">' + escHtml(mesa.nombre) + '</span>';\n    if (ticket.nombre) {\n      h += '<span class=\"mmodal-title-cliente\">— ' + escHtml(ticket.nombre) + '</span>';\n    }\n    h += '</div></div>';\n    return h;\n  }\n\n  function showCerrarConfirm(mesa, ticket) {\n    showPagoSelect(mesa, ticket);\n  }\n\n  function showPagoSelect(mesa, ticket) {\n    var h = buildCerrarHeader(mesa, ticket);\n    h += '<div class=\"mmodal-cerrar-confirm\">';\n    h += '<p class=\"mmodal-cerrar-confirm__msg\">¿Cómo pagó el cliente?</p>';\n    h += '<p class=\"mmodal-cerrar-confirm__sub\">Selecciona el método de pago para cerrar el ticket.</p>';\n    h += '<div class=\"mmodal-pago-btns\">';\n    h += '<button class=\"mmodal-pago-btn\" id=\"pago-efectivo\">';\n    h += '<span class=\"mmodal-pago-btn__icon\">💵</span>';\n    h += '<span class=\"mmodal-pago-btn__label\">Efectivo</span>';\n    h += '</button>';\n    h += '<button class=\"mmodal-pago-btn\" id=\"pago-tarjeta\">';\n    h += '<span class=\"mmodal-pago-btn__icon\">💳</span>';\n    h += '<span class=\"mmodal-pago-btn__label\">Tarjeta</span>';\n    h += '</button>';\n    h += '</div>';\n    h += '<div class=\"mmodal-cerrar-confirm__btns\" style=\"margin-top:0\">';\n    h += '<button class=\"mmodal-btn mmodal-btn--ghost\" id=\"cc-volver-ticket\">← Volver</button>';\n    h += '</div>';\n    h += '</div>';\n\n    modalContent.innerHTML = h;\n\n    modalContent.querySelector('#pago-efectivo').addEventListener('click', function() {\n      showPagoConfirm(mesa, ticket, 'efectivo');\n    });\n    modalContent.querySelector('#pago-tarjeta').addEventListener('click', function() {\n      showPagoConfirm(mesa, ticket, 'tarjeta');\n    });\n    modalContent.querySelector('#cc-volver-ticket').addEventListener('click', function() {\n      commandaItems    = [];\n      selectedComensal = 0;\n      modalContent.innerHTML = buildModalContent(mesa, 'con-ticket', null, ticket);\n      bindModalActions(mesa, null, ticket);\n    });\n  }\n\n  function showPagoConfirm(mesa, ticket, metodoPago) {\n    var label = metodoPago === 'efectivo' ? 'Efectivo' : 'Tarjeta';\n    var h = buildCerrarHeader(mesa, ticket);\n    h += '<div class=\"mmodal-cerrar-confirm\">';\n    h += '<div class=\"mmodal-cerrar-confirm__icon\">⚠</div>';\n    h += '<p class=\"mmodal-cerrar-confirm__msg\">¿Cerrar el ticket de <strong>' +\n         escHtml(mesa.nombre) + '</strong>?</p>';\n    h += '<p class=\"mmodal-cerrar-confirm__sub\">Método de pago: <span class=\"mmodal-pago-badge\">' +\n         escHtml(label) + '</span></p>';\n    h += '<p class=\"mmodal-cerrar-confirm__sub\" style=\"margin-top:4px\">Esta acción no se puede deshacer.</p>';\n    h += '<div class=\"mmodal-cerrar-confirm__btns\">';\n    h += '<button class=\"mmodal-btn mmodal-btn--ghost\" id=\"cc-volver-pago\">← Volver</button>';\n    h += '<button class=\"mmodal-btn mmodal-btn--danger\" id=\"cc-confirm\">Cerrar ticket</button>';\n    h += '</div>';\n    h += '</div>';\n\n    modalContent.innerHTML = h;\n\n    modalContent.querySelector('#cc-volver-pago').addEventListener('click', function() {\n      showPagoSelect(mesa, ticket);\n    });\n\n    (function(tid, mp, m) {\n      modalContent.querySelector('#cc-confirm').addEventListener('click', function() {\n        apiCerrarTicket(tid, mp, m);\n      });\n    })(ticket.id, metodoPago, mesa);\n  }\n\n  // ── Pantalla QR de feedback ───────────────────────────────\n  function showFeedbackQR(token, mesaNombre) {\n    var url = window.location.origin + '/feedback?token=' + token;\n    var h = '<div class=\"mmodal-header\"><div class=\"mmodal-header-id\">';\n    h += '<span class=\"mmodal-title\">' + escHtml(mesaNombre) + '</span>';\n    h += '<span class=\"mmodal-title-cliente\">— Ticket cerrado</span>';\n    h += '</div></div>';\n    h += '<div class=\"mmodal-feedback-qr\">';\n    h += '<p class=\"mmodal-feedback-qr__title\">Invita al comensal a dejar su reseña</p>';\n    h += '<div class=\"mmodal-feedback-qr__canvas\" id=\"qr-canvas\"></div>';\n    h += '<p class=\"mmodal-feedback-qr__url\">' + escHtml(url) + '</p>';\n    h += '<div class=\"mmodal-cerrar-confirm__btns\">';\n    h += '<button class=\"mmodal-btn mmodal-btn--ghost\" id=\"qr-cerrar\">Cerrar</button>';\n    h += '</div>';\n    h += '</div>';\n\n    modalContent.innerHTML = h;\n\n    if (typeof qrcode === 'function') {\n      var qr = qrcode(0, 'M');\n      qr.addData(url);\n      qr.make();\n      var qrEl = document.getElementById('qr-canvas');\n      if (qrEl) qrEl.innerHTML = qr.createImgTag(5, 8);\n    }\n\n    modalContent.querySelector('#qr-cerrar').addEventListener('click', function() {\n      closeModal();\n      silentRefresh();\n    });\n  }\n\n  // ── Llamadas API ──────────────────────────────────────────\n  function apiPost(url, data) {\n    fetch(url, {\n      method:  'POST',\n      headers: { 'Content-Type': 'application/json' },\n      body:    JSON.stringify(data)\n    })\n    .then(function(res) { return res.json(); })\n    .then(function(result) {\n      if (result.ok) {\n        closeModal();\n        silentRefresh();\n      } else {\n        alert(result.msg || 'Error al procesar la solicitud');\n      }\n    })\n    .catch(function() { alert('Error de conexión'); });\n  }\n\n  function apiAbrirTicket(mesaId, mesa2Id, comensales, reservaId, nombre) {\n    apiPost('/api/abrir-ticket', {\n      mesa_id: mesaId, mesa2_id: mesa2Id,\n      comensales: comensales, reservacion_id: reservaId,\n      nombre: nombre || null\n    });\n  }\n\n  // Abre un ticket de Llevar y va directo al POS sin cerrar el modal\n  function apiAbrirLlevarTicket(mesa, comensales, nombre) {\n    fetch('/api/abrir-ticket', {\n      method:  'POST',\n      headers: { 'Content-Type': 'application/json' },\n      body:    JSON.stringify({\n        mesa_id:        mesa.id,\n        comensales:     comensales,\n        nombre:         nombre || null,\n        allow_multiple: true\n      })\n    })\n    .then(function(r) { return r.json(); })\n    .then(function(result) {\n      if (result.ok) {\n        var newTicket = {\n          id:            result.id,\n          mesa_id:       mesa.id,\n          nombre:        nombre,\n          comensales:    comensales,\n          hora_apertura: new Date().toISOString().replace('T', ' ').substring(0, 19)\n        };\n        silentRefresh();\n        commandaItems    = [];\n        selectedComensal = 0;\n        modalContent.innerHTML = buildModalContent(mesa, 'con-ticket', null, newTicket);\n        bindModalActions(mesa, null, newTicket);\n      } else {\n        alert(result.msg || 'Error al crear el pedido');\n      }\n    })\n    .catch(function() { alert('Error de conexión'); });\n  }\n\n  function apiLiberarReservacion(reservaId) {\n    apiPost('/api/liberar-reservacion', { reservacion_id: reservaId });\n  }\n\n  function apiCerrarTicket(ticketId, metodoPago, mesa) {\n    fetch('/api/cerrar-ticket', {\n      method:  'POST',\n      headers: { 'Content-Type': 'application/json' },\n      body:    JSON.stringify({ ticket_id: ticketId, metodo_pago: metodoPago })\n    })\n    .then(function(res) { return res.json(); })\n    .then(function(result) {\n      if (result.ok) {\n        showFeedbackQR(result.token, mesa ? mesa.nombre : '');\n      } else {\n        alert(result.msg || 'Error al cerrar el ticket');\n      }\n    })\n    .catch(function() { alert('Error de conexión'); });\n  }\n\n  function apiEnviarComanda(ticketId) {\n    var payload = { ticket_id: ticketId, items: [] };\n    for (var i = 0; i < commandaItems.length; i++) {\n      var ci = commandaItems[i];\n      payload.items.push({\n        nombre:    ci.n,\n        precio:    ci.p,\n        categoria: ci.categoria,\n        area_id:   ci.area_id,\n        comensal:  ci.comensal === 0 ? null : ci.comensal,\n        cantidad:  ci.qty,\n        nota:      ci.nota && ci.nota.trim() ? ci.nota.trim() : null\n      });\n    }\n\n    fetch('/api/enviar-comanda', {\n      method:  'POST',\n      headers: { 'Content-Type': 'application/json' },\n      body:    JSON.stringify(payload)\n    })\n    .then(function(res) { return res.json(); })\n    .then(function(result) {\n      if (result.ok) {\n        commandaItems = [];\n        renderComandaCart();\n        updateEnviarBtn();\n        // Cambiar a tab Ticket (col 3) para ver el estado\n        var tabResumen = modalContent.querySelector('[data-tab=\"resumen\"]');\n        if (tabResumen) tabResumen.click();\n        // En desktop: refrescar columna 3 directamente\n        if (window.innerWidth >= 768) renderResumen(ticketId);\n      } else {\n        alert(result.msg || 'Error al enviar la comanda');\n      }\n    })\n    .catch(function() { alert('Error de conexión'); });\n  }\n\n  function apiEntregarItem(itemId, ticketId) {\n    fetch('/api/entregar-item', {\n      method:  'POST',\n      headers: { 'Content-Type': 'application/json' },\n      body:    JSON.stringify({ item_id: itemId })\n    })\n    .then(function(r) { return r.json(); })\n    .then(function(result) { if (result.ok) renderResumen(ticketId); });\n  }\n\n  function showCancelItemConfirm(itemId, nombre, ticketId) {\n    var overlay = document.createElement('div');\n    overlay.className = 'mmodal-cancel-confirm-overlay';\n    overlay.innerHTML =\n      '<div class=\"mmodal-cancel-confirm\">' +\n        '<p class=\"mmodal-cancel-confirm__msg\">¿Cancelar <strong>' + escHtml(nombre) + '</strong>?</p>' +\n        '<p class=\"mmodal-cancel-confirm__sub\">El área dejará de prepararlo. Esta acción no se puede deshacer.</p>' +\n        '<div class=\"mmodal-cancel-confirm__btns\">' +\n          '<button class=\"mmodal-btn mmodal-btn--ghost\" id=\"cc-volver\">No, conservar</button>' +\n          '<button class=\"mmodal-btn mmodal-btn--danger\" id=\"cc-confirm\">Sí, cancelar</button>' +\n        '</div>' +\n      '</div>';\n    var panel = modalContent.querySelector('#mmodal-panel-resumen');\n    if (panel) panel.appendChild(overlay);\n    overlay.querySelector('#cc-volver').addEventListener('click', function() { overlay.remove(); });\n    overlay.querySelector('#cc-confirm').addEventListener('click', function() {\n      overlay.remove();\n      apiCancelarItem(itemId, ticketId);\n    });\n  }\n\n  function apiCancelarItem(itemId, ticketId) {\n    fetch('/api/cancelar-item', {\n      method:  'POST',\n      headers: { 'Content-Type': 'application/json' },\n      body:    JSON.stringify({ item_id: itemId })\n    })\n    .then(function(r) { return r.json(); })\n    .then(function(result) {\n      if (result.ok) renderResumen(ticketId);\n      else alert(result.msg || 'No se pudo cancelar el platillo');\n    })\n    .catch(function() { alert('Error de conexión'); });\n  }\n\n  // ── Calendario personalizado de fecha ────────────────────\n  function initMapaCalendar() {\n    var picker     = document.getElementById('mapa-date-picker');\n    var displayBtn = document.getElementById('mapa-date-display');\n    var calEl      = document.getElementById('mapa-calendar');\n    if (!picker || !displayBtn || !calEl) return;\n\n    var labelEl = document.getElementById('mapa-cal-label');\n    var gridEl  = document.getElementById('mapa-cal-grid');\n    var prevBtn = document.getElementById('mapa-cal-prev');\n    var nextBtn = document.getElementById('mapa-cal-next');\n\n    var MONTHS = ['Enero','Febrero','Marzo','Abril','Mayo','Junio',\n                  'Julio','Agosto','Septiembre','Octubre','Noviembre','Diciembre'];\n\n    function pad(n) { return n < 10 ? '0' + n : '' + n; }\n\n    function toDisplay(d) {\n      return pad(d.getDate()) + ' · ' + MONTHS[d.getMonth()].substring(0, 3) + ' ' + d.getFullYear();\n    }\n\n    var initVal   = fechaInput ? fechaInput.value : new Date().toISOString().slice(0, 10);\n    var parts     = initVal.split('-');\n    var selected  = new Date(+parts[0], +parts[1] - 1, +parts[2]);\n    var curYear   = selected.getFullYear();\n    var curMonth  = selected.getMonth();\n\n    function renderGrid() {\n      if (labelEl) labelEl.textContent = MONTHS[curMonth] + ' ' + curYear;\n      if (!gridEl) return;\n      gridEl.innerHTML = '';\n\n      var first = new Date(curYear, curMonth, 1).getDay();\n      var days  = new Date(curYear, curMonth + 1, 0).getDate();\n      var today = new Date(); today.setHours(0, 0, 0, 0);\n\n      for (var i = 0; i < first; i++) {\n        var empty = document.createElement('span');\n        empty.className = 'mapa-cal__day mapa-cal__day--empty';\n        gridEl.appendChild(empty);\n      }\n\n      for (var d = 1; d <= days; d++) {\n        (function(day) {\n          var btn  = document.createElement('button');\n          btn.type = 'button';\n          btn.className = 'mapa-cal__day';\n          btn.textContent = day;\n\n          var date = new Date(curYear, curMonth, day);\n          date.setHours(0, 0, 0, 0);\n\n          if (date.getTime() === today.getTime())    btn.classList.add('mapa-cal__day--today');\n          if (selected && date.getTime() === selected.getTime()) btn.classList.add('mapa-cal__day--selected');\n\n          btn.addEventListener('click', function() {\n            selected = date;\n            var val  = date.getFullYear() + '-' + pad(date.getMonth() + 1) + '-' + pad(date.getDate());\n            if (fechaInput) fechaInput.value = val;\n            displayBtn.textContent = toDisplay(date);\n            closeCal();\n            stopPolling();\n            fetchData(val, false);\n            startPolling();\n          });\n\n          gridEl.appendChild(btn);\n        })(d);\n      }\n    }\n\n    function openCal()  { calEl.classList.add('mapa-cal--open'); calEl.setAttribute('aria-hidden', 'false'); renderGrid(); }\n    function closeCal() { calEl.classList.remove('mapa-cal--open'); calEl.setAttribute('aria-hidden', 'true'); }\n\n    displayBtn.textContent = toDisplay(selected);\n    displayBtn.addEventListener('click', function(e) {\n      e.stopPropagation();\n      calEl.classList.contains('mapa-cal--open') ? closeCal() : openCal();\n    });\n\n    if (prevBtn) {\n      prevBtn.addEventListener('click', function(e) {\n        e.stopPropagation();\n        curMonth--;\n        if (curMonth < 0) { curMonth = 11; curYear--; }\n        renderGrid();\n      });\n    }\n\n    if (nextBtn) {\n      nextBtn.addEventListener('click', function(e) {\n        e.stopPropagation();\n        curMonth++;\n        if (curMonth > 11) { curMonth = 0; curYear++; }\n        renderGrid();\n      });\n    }\n\n    document.addEventListener('click', function(e) {\n      if (!picker.contains(e.target)) closeCal();\n    });\n  }\n\n  // ── Fetch datos ───────────────────────────────────────────\n  function fetchData(fecha, silent) {\n    if (!silent) {\n      if (loadingEl) loadingEl.classList.remove('hidden');\n      reservasList.innerHTML =\n        '<div class=\"mapa-empty-state\"><span class=\"mapa-empty-icon\">◌</span><span>Cargando…</span></div>';\n    }\n    fetch('/api/mapa?fecha=' + encodeURIComponent(fecha))\n      .then(function(res) { return res.json(); })\n      .then(function(data) {\n        if (data.ok === false) {\n          if (!silent) {\n            reservasList.innerHTML =\n              '<div class=\"mapa-empty-state mapa-empty-state--error\">' +\n                '<span class=\"mapa-empty-icon\">⚠</span>' +\n                '<span>' + (data.hint || data.error || 'Error de servidor') + '</span>' +\n              '</div>';\n            if (loadingEl) loadingEl.classList.add('hidden');\n          }\n          return;\n        }\n        mesas         = data.mesas         || [];\n        reservaciones = data.reservaciones  || [];\n        tickets       = data.tickets        || [];\n        if (!silent) renderMesas();\n        renderEstados();\n        renderSidebar();\n        if (loadingEl) loadingEl.classList.add('hidden');\n      })\n      .catch(function() {\n        if (!silent) {\n          reservasList.innerHTML =\n            '<div class=\"mapa-empty-state mapa-empty-state--error\">' +\n              '<span class=\"mapa-empty-icon\">⚠</span><span>Error al cargar datos.</span>' +\n            '</div>';\n          if (loadingEl) loadingEl.classList.add('hidden');\n        }\n      });\n  }\n\n  function silentRefresh() {\n    fetchData(fechaInput ? fechaInput.value : new Date().toISOString().slice(0, 10), true);\n  }\n\n  // ── Polling en tiempo real (cada 30 s) ────────────────────\n  function startPolling() {\n    stopPolling();\n    pollTimer = setInterval(silentRefresh, 30000);\n  }\n  function stopPolling() {\n    if (pollTimer) { clearInterval(pollTimer); pollTimer = null; }\n  }\n\n  // ── Modo en vivo ──────────────────────────────────────────\n  function syncLive() {\n    var min = snapTo30(new Date().getHours() * 60 + new Date().getMinutes());\n    min = Math.max(510, Math.min(1320, min));\n    sliderMin = min;\n    renderEstados();\n    renderSidebar();\n  }\n\n  function activateLive() {\n    isLive = true;\n    if (liveBadge) liveBadge.classList.add('mapa-live-badge--active');\n    if (ahoraBtn)  ahoraBtn.classList.add('mapa-ahora-btn--active');\n    syncLive();\n    if (liveInterval) clearInterval(liveInterval);\n    liveInterval = setInterval(syncLive, 60000);\n    startPolling();\n  }\n\n  function deactivateLive() {\n    isLive = false;\n    if (liveBadge) liveBadge.classList.remove('mapa-live-badge--active');\n    if (ahoraBtn)  ahoraBtn.classList.remove('mapa-ahora-btn--active');\n    if (liveInterval) { clearInterval(liveInterval); liveInterval = null; }\n  }\n\n  // ── Eventos ───────────────────────────────────────────────\n  initMapaCalendar();\n\n  if (modalBd)    modalBd.addEventListener('click', closeModal);\n  if (modalClose) modalClose.addEventListener('click', closeModal);\n  document.addEventListener('keydown', function(e) {\n    if (e.key === 'Escape') closeModal();\n  });\n\n  // ── Init ──────────────────────────────────────────────────\n  sliderMin = Math.max(510, Math.min(1320, snapTo30(new Date().getHours() * 60 + new Date().getMinutes())));\n  fetchData(fechaInput ? fechaInput.value : new Date().toISOString().slice(0, 10), false);\n  activateLive();\n}\n\n// Auto-inicializar independientemente de boot()\n(function() {\n  function tryInitMapa() {\n    if (document.getElementById('mapa-canvas')) initMapa();\n  }\n  if (document.readyState === 'loading') {\n    document.addEventListener('DOMContentLoaded', tryInitMapa);\n  } else {\n    tryInitMapa();\n  }\n})();\n","/* Menú — tabs, lista de platos y preview */\r\nvar currentCat = 0;\r\n\r\nfunction initMenu() {\r\n  var tabs = $(\"#menuTabs\"), list = $(\"#menuList\");\r\n  var pcCat = $(\"#pcCat\"), pcName = $(\"#pcName\"), pcCount = $(\"#pcCount\"), frame = $(\"#previewFrame\");\r\n\r\n  list.innerHTML = '<p style=\"padding:2rem;opacity:.5\">Cargando menú…</p>';\r\n  // Realizamos peticion al backend por medio de Fetch\r\n  fetch('/menu')\r\n    .then(function(r) { return r.json(); })\r\n    .then(function(data) {\r\n      var imgCache = {};\r\n      list.innerHTML = '';\r\n\r\n      function preview(cat, dish) {\r\n        pcCat.textContent = cat.label;\r\n        pcName.textContent = dish ? dish.n : (cat.kicker || cat.label);\r\n\r\n        /* Descomentar para renderizar imagen individual por platillo:\r\n        if (!dish || !dish.img) return;\r\n        var img = imgCache[dish.img];\r\n        if (!img) {\r\n          img = document.createElement(\"img\");\r\n          img.src = dish.img; img.alt = dish.n;\r\n          frame.insertBefore(img, frame.firstChild);\r\n          imgCache[dish.img] = img;\r\n        }\r\n        $$(\".menu__preview-frame img\").forEach(function(im) { im.classList.remove(\"show\"); });\r\n        img.classList.add(\"show\");\r\n        frame.setAttribute(\"data-zoom-src\", dish.img);\r\n        frame.setAttribute(\"data-zoom-name\", dish.n);\r\n        frame.setAttribute(\"data-zoom-cat\", cat.label);\r\n        */\r\n\r\n        if (!cat.img) return;\r\n        var img = imgCache[cat.img];\r\n        if (!img) {\r\n          img = document.createElement(\"img\");\r\n          img.src = cat.img; img.alt = cat.label;\r\n          frame.insertBefore(img, frame.firstChild);\r\n          imgCache[cat.img] = img;\r\n        }\r\n        $$(\".menu__preview-frame img\").forEach(function(im) { im.classList.remove(\"show\"); });\r\n        img.classList.add(\"show\");\r\n        frame.setAttribute(\"data-zoom-src\", cat.img);\r\n        frame.setAttribute(\"data-zoom-name\", cat.label);\r\n        frame.setAttribute(\"data-zoom-cat\", cat.label);\r\n      }\r\n\r\n      function renderList(catIndex) {\r\n        var cat = data[catIndex];\r\n        list.innerHTML = \"\";\r\n        pcCount.textContent = cat.dishes.length + \" platillos\";\r\n        cat.dishes.forEach(function(d, j) {\r\n          var row = document.createElement(\"div\");\r\n          row.className = \"dish\";\r\n          var tags = (d.tags || []).map(function(t) { return '<span class=\"dish__tag\">' + t + '</span>'; }).join(\"\");\r\n\r\n          /* Descomentar para miniatura individual por platillo:\r\n          var thumb = d.img\r\n            ? '<div class=\"dish__thumb\" data-zoom data-zoom-cat=\"' + cat.label + '\"><img src=\"' + d.img + '\" alt=\"' + d.n + '\" loading=\"lazy\" /></div>'\r\n            : '';\r\n          */\r\n          var thumb = '';\r\n\r\n          row.innerHTML =\r\n            thumb +\r\n            '<span class=\"dish__idx\">' + String(j + 1).padStart(2, \"0\") + '</span>' +\r\n            '<div class=\"dish__main\"><h4>' + d.n + '</h4>' +\r\n            (d.d ? '<p>' + d.d + '</p>' : '') +\r\n            (tags ? '<div class=\"dish__tags\">' + tags + '</div>' : '') +\r\n            '</div>' +\r\n            '<span class=\"dish__price\">$' + d.p + '<small> mxn</small></span>';\r\n          row.addEventListener(\"mouseenter\", function() {\r\n            $$(\".dish\").forEach(function(x) { x.classList.remove(\"active\"); });\r\n            row.classList.add(\"active\");\r\n            preview(cat, d);\r\n          });\r\n          list.appendChild(row);\r\n        });\r\n        if (!reduce && window.gsap) gsap.fromTo(list.children, { opacity: 0, y: 24 }, { opacity: 1, y: 0, duration: 0.6, stagger: 0.05, ease: \"power3.out\" });\r\n        preview(cat, cat.dishes[0]);\r\n        if (list.firstChild) list.firstChild.classList.add(\"active\");\r\n      }\r\n\r\n      function selectCat(i) {\r\n        currentCat = i;\r\n        $$(\".menu__tab\").forEach(function(t, k) { t.classList.toggle(\"active\", k === i); });\r\n        renderList(i);\r\n        if (window.ScrollTrigger) ScrollTrigger.refresh();\r\n      }\r\n\r\n      data.forEach(function(cat, i) {\r\n        var b = document.createElement(\"button\");\r\n        b.className = \"menu__tab\" + (i === 0 ? \" active\" : \"\");\r\n        b.innerHTML = cat.label + '<span class=\"count\">' + String(cat.dishes.length).padStart(2, \"0\") + '</span>';\r\n        b.addEventListener(\"click\", function() { selectCat(i); });\r\n        tabs.appendChild(b);\r\n      });\r\n\r\n      renderList(0);\r\n    })\r\n    .catch(function() {\r\n      list.innerHTML = '<p style=\"padding:2rem;opacity:.5\">No se pudo cargar el menú.</p>';\r\n    });\r\n}\r\n","/* Navegación overlay */\r\nfunction initNav() {\r\n  var toggle = $(\"#navToggle\");\r\n  toggle.addEventListener(\"click\", function() { body.classList.toggle(\"nav-open\"); });\r\n\r\n  $$(\"[data-nav]\").forEach(function(a) {\r\n    a.addEventListener(\"click\", function(e) {\r\n      e.preventDefault();\r\n      var id = a.getAttribute(\"href\");\r\n      body.classList.remove(\"nav-open\");\r\n      setTimeout(function() { scrollTo(id); }, 200);\r\n    });\r\n  });\r\n\r\n  // brand + rail + footer + anchors in-page\r\n  $$('a[href^=\"#\"]').forEach(function(a) {\r\n    if (a.hasAttribute(\"data-nav\")) return;\r\n    a.addEventListener(\"click\", function(e) {\r\n      var id = a.getAttribute(\"href\");\r\n      if (id.length < 2 || !$(id)) return;\r\n      e.preventDefault();\r\n      scrollTo(id);\r\n    });\r\n  });\r\n\r\n  document.addEventListener(\"keydown\", function(e) {\r\n    if (e.key === \"Escape\") body.classList.remove(\"nav-open\");\r\n  });\r\n}\r\n","/* Rail de secciones (estado activo) */\r\nfunction initRail() {\r\n  var links = $$(\"#rail a\");\r\n  var map = {};\r\n  links.forEach(function(l) { map[l.getAttribute(\"data-rail\")] = l; });\r\n\r\n  var io = new IntersectionObserver(function(entries) {\r\n    entries.forEach(function(en) {\r\n      if (en.isIntersecting) {\r\n        links.forEach(function(l) { l.classList.remove(\"active\"); });\r\n        var m = map[en.target.id];\r\n        if (m) m.classList.add(\"active\");\r\n      }\r\n    });\r\n  }, { rootMargin: \"-45% 0px -45% 0px\" });\r\n\r\n  Object.keys(map).forEach(function(id) {\r\n    var s = document.getElementById(id);\r\n    if (s) io.observe(s);\r\n  });\r\n}\r\n","/* Animaciones de reveal + parallax imágenes */\r\nfunction initReveals() {\r\n  if (reduce) { body.classList.add(\"no-anim\"); return; }\r\n\r\n  $$(\"[data-reveal]\").forEach(function(el) {\r\n    if (el.closest(\".hero__inner\")) return;\r\n    gsap.to(el, {\r\n      opacity: 1, y: 0, duration: 1, ease: \"power3.out\",\r\n      scrollTrigger: { trigger: el, start: \"top 88%\" }\r\n    });\r\n  });\r\n\r\n  $$(\"[data-parallax-img] img, [data-parallax-img]\").forEach(function(wrap) {\r\n    var img = wrap.tagName === \"IMG\" ? wrap : wrap.querySelector(\"img\");\r\n    if (!img) return;\r\n    gsap.fromTo(img, { yPercent: -8 }, {\r\n      yPercent: 8, ease: \"none\",\r\n      scrollTrigger: { trigger: wrap, start: \"top bottom\", end: \"bottom top\", scrub: true }\r\n    });\r\n  });\r\n}\r\n","/* Panel de Tweaks */\r\nfunction initTweaks() {\r\n  var panel = $(\"#tweaks\");\r\n\r\n  function setHero(v) {\r\n    body.setAttribute(\"data-hero\", v);\r\n    $$('[data-tw=\"hero\"] .tw-opt').forEach(function(b) { b.classList.toggle(\"sel\", b.dataset.val === v); });\r\n    if (window.ScrollTrigger) ScrollTrigger.refresh();\r\n  }\r\n\r\n  function setAccentTw(v) {\r\n    applyAccent(v);\r\n    $$('[data-tw=\"accent\"] .tw-swatch').forEach(function(b) { b.classList.toggle(\"sel\", b.dataset.val === v); });\r\n  }\r\n\r\n  function setSwitch(name, on) {\r\n    var sw = $('.tw-switch[data-tw=\"' + name + '\"]');\r\n    if (sw) sw.classList.toggle(\"on\", !!on);\r\n    if (name === \"cursor\") setCursorEnabled(on);\r\n    if (name === \"smooth\") { on ? startLenis() : stopLenis(); }\r\n    if (name === \"anim\") { body.classList.toggle(\"no-anim\", !on); }\r\n  }\r\n\r\n  // Inicializar desde defaults\r\n  setHero(T.hero);\r\n  setAccentTw(T.accent);\r\n  setSwitch(\"cursor\", T.cursor);\r\n  setSwitch(\"smooth\", T.smooth);\r\n  setSwitch(\"anim\", T.anim);\r\n\r\n  // Conectar controles\r\n  $$('[data-tw=\"hero\"] .tw-opt').forEach(function(b) {\r\n    b.addEventListener(\"click\", function() { setHero(b.dataset.val); persist({ hero: b.dataset.val }); });\r\n  });\r\n  $$('[data-tw=\"accent\"] .tw-swatch').forEach(function(b) {\r\n    b.addEventListener(\"click\", function() { setAccentTw(b.dataset.val); persist({ accent: b.dataset.val }); });\r\n  });\r\n  [\"cursor\", \"smooth\", \"anim\"].forEach(function(name) {\r\n    var sw = $('.tw-switch[data-tw=\"' + name + '\"]');\r\n    if (sw) sw.addEventListener(\"click\", function() {\r\n      var on = !sw.classList.contains(\"on\");\r\n      setSwitch(name, on);\r\n      persist({ [name]: on });\r\n    });\r\n  });\r\n\r\n  $(\"#twClose\").addEventListener(\"click\", function() {\r\n    panel.classList.remove(\"open\");\r\n    try { window.parent.postMessage({ type: \"__edit_mode_dismissed\" }, \"*\"); } catch (e) {}\r\n  });\r\n\r\n  function persist(obj) {\r\n    try { window.parent.postMessage({ type: \"__edit_mode_set_keys\", edits: obj }, \"*\"); } catch (e) {}\r\n  }\r\n\r\n  window.addEventListener(\"message\", function(e) {\r\n    var d = e.data || {};\r\n    if (d.type === \"__activate_edit_mode\") panel.classList.add(\"open\");\r\n    else if (d.type === \"__deactivate_edit_mode\") panel.classList.remove(\"open\");\r\n  });\r\n\r\n  try { window.parent.postMessage({ type: \"__edit_mode_available\" }, \"*\"); } catch (e) {}\r\n}\r\n"]}
